    #[test]
    fn diff_derangement_subfactorial() {
        // A bug-hunt-116 lock (it454): DERANGEMENTS (the subfactorial !n) -- the number of permutations of n
        // elements with NO fixed point (no element left in its original position) -- certified by cross-validating
        // TWO independent recurrences. This extends the combinatorics family with a COUNT distinct from its
        // neighbors: permutations (it357) ENUMERATE all n! orderings, Stirling (it453) counts set partitions,
        // whereas the derangement count is the fixed-point-free subset. Recurrence one is the classic
        // D(n) = (n-1)*(D(n-1) + D(n-2)) (the displaced-element argument); recurrence two is the equivalent
        // D(n) = n*D(n-1) + (-1)^n (the inclusion-exclusion alternating form). They share no structure -- one is a
        // two-term branching recurrence, the other a linear recurrence with an alternating +/-1 correction -- so
        // their agreement (cross == true) is strong evidence both are right.
        //   !0=1 (the empty permutation vacuously deranges) / !1=0 (the one fixed point is unavoidable)
        //   !2=1, !3=2, !4=9, !5=44, !6=265    (the standard subfactorial values)
        //   cross = true                        (d1(6) == d2(6): the two recurrences agree at 265)
        // Byte-identical on interp/KVM (native per the sweep). Confirms that the base cases seed !0=1 and !1=0,
        // that the two-term recurrence weights (D(n-1)+D(n-2)) by n-1, that the alternating-sign recurrence adds
        // +1 for even n and -1 for odd n (the 0-1 negative-literal form), that the two formulas produce the same
        // subfactorial, that the values match the known sequence, and that all three engines agree. This is the
        // "how many ways can nobody get their own hat back" count an AI writes for probability or combinatorics;
        // two independent recurrences agreeing catches an off-by-one or a sign error in either. A non-sort lock
        // certifying the derangement count via two cross-checked recurrences.
        let src = r#"fun d1(n: Int) -> Int {
    if n == 0 { 1 } else if n == 1 { 0 } else { (n - 1) * (d1(n - 1) + d1(n - 2)) }
}
fun d2(n: Int) -> Int {
    if n == 0 { 1 }
    else { let sign = if n % 2 == 0 { 1 } else { 0 - 1 }; n * d2(n - 1) + sign }
}
fun probe() -> Str {
    let a0 = d1(0)
    let a1 = d1(1)
    let a2 = d1(2)
    let a3 = d1(3)
    let a4 = d1(4)
    let a5 = d1(5)
    let a6 = d1(6)
    let cross = d1(6) == d2(6)
    "d0={a0}|d1={a1}|d2={a2}|d3={a3}|d4={a4}|d5={a5}|d6={a6}|cross={cross}"
}
"#;
        assert_eq!(
            differential(src),
            "d0=1|d1=0|d2=1|d3=2|d4=9|d5=44|d6=265|cross=true"
        );
    }

    #[test]
    fn diff_euclidean_division_identity() {
        // A certification lock (it492, from bug-hunt batch 129 -- 10 probes across string/int/float/list/Map/Set/
        // Option shapes came back byte-identical, so the subtlest untouched corner is locked): the EUCLIDEAN DIVISION
        // IDENTITY for div_euclid/rem_euclid. Where diff_int_rem_div_euclid (it195) pins the VALUES for the four
        // sign combinations (and contrasts them with % and /), THIS certifies the two defining INVARIANTS that make
        // (q, r) a valid Euclidean division -- a SPEC-PROPERTY cross-check (like newton_isqrt's r^2 <= n < (r+1)^2):
        //   RECONSTRUCTION:  div_euclid(n,d) * d + rem_euclid(n,d) == n   (the pair actually divides n)
        //   BOUNDED REMAINDER:  0 <= rem_euclid(n,d) < |d|                (the Euclidean remainder is non-negative
        //                                                                 and strictly less than the divisor's magnitude)
        // Checked across all four sign combinations of (7,3) plus (20,6),(-20,6),(0,5),(100,7). The remainder bound
        // is what distinguishes Euclidean division from truncating (%): (-7).rem_euclid(3) = 2 lies in [0,3), and
        // 2 + (-3)*3 = -7 reconstructs. Byte-identical on interp/KVM (native per the sweep). Confirms that q*d + r
        // reconstructs n for every sign of n and d, that r is always in [0,|d|), that these hold at the n=0 edge,
        // and that all three engines agree. This is the division invariant an AI relies on when reasoning about
        // modular arithmetic or clock/index wrapping; a backend whose div_euclid rounded toward zero instead of
        // negative infinity would satisfy neither invariant for negative n. A non-sort lock certifying the
        // Euclidean division identity.
        let src = r#"fun absI(x: Int) -> Int { if x < 0 { 0 - x } else { x } }
fun recon(n: Int, d: Int) -> Bool { n.div_euclid(d) * d + n.rem_euclid(d) == n }
fun bounded(n: Int, d: Int) -> Bool {
    let r = n.rem_euclid(d)
    r >= 0 && r < absI(d)
}
fun probe() -> Str {
    let r1 = recon(7, 3) && recon(0 - 7, 3) && recon(7, 0 - 3) && recon(0 - 7, 0 - 3)
    let r2 = recon(20, 6) && recon(0 - 20, 6) && recon(0, 5) && recon(100, 7)
    let b1 = bounded(7, 3) && bounded(0 - 7, 3) && bounded(7, 0 - 3) && bounded(0 - 7, 0 - 3)
    let b2 = bounded(20, 6) && bounded(0 - 20, 6) && bounded(0, 5) && bounded(100, 7)
    let e7 = (0 - 7).rem_euclid(3)
    let q7 = (0 - 7).div_euclid(3)
    "r1={r1}|r2={r2}|b1={b1}|b2={b2}|e7={e7}|q7={q7}"
}
"#;
        assert_eq!(
            differential(src),
            "r1=true|r2=true|b1=true|b2=true|e7=2|q7=-3"
        );
    }

