        //   largestRect([5,5,5]) = 15             (flat bars: full height over full width)
        //   largestRect([1]) = 1                  (a single bar)
        //   largestRect([]) = 0                   (no bars)
        //   largestRect([6,2,5,4,5,1,6]) = 12     (bars 5,4,5: height 4 over width 3)
