    #[test]
    fn diff_priority_queue_sorted_insert() {
        // A bug-hunt-51 lock (it321): a priority queue via ORDERED INSERTION into a sorted list. Each insert
        // splits the queue at the position where the new task's priority belongs -- take_while(prio <=
        // t.prio) is the prefix, drop_while(prio <= t.prio) is the suffix -- and reassembles [prefix, [t],
        // suffix] to keep the queue sorted by priority. Building the whole queue is a fold of insert over an
        // unsorted task list; the front is the highest-priority (min-prio) task. This is the sorted-insert
        // priority queue an AI writes for scheduling / event queues / a Dijkstra frontier -- distinct from a
        // BST (it313) or a composite-key sort (it305): the invariant is maintained incrementally at each
        // insert via a take_while/drop_while split, not by re-sorting.
        //   insert c(3), a(1), e(5), b(2), d(4) one at a time -> queue ordered by prio: a,b,c,d,e
        //   order = "abcde" ; front = a@1 (min priority)
        // Byte-identical on interp/KVM (native per the sweep). Confirms take_while collects the <=-priority
        // prefix and drop_while the strictly-greater suffix (complementary at the same boundary, per it282),
        // that flatten reassembles the list with t inserted at the right spot, that folding insert from an
        // empty seed threads the growing sorted queue, and that first() returns the min-priority front. This
        // is insertion into a sorted structure keeping an ordering invariant per-step; a backend where
        // take_while/drop_while disagreed on the split point would insert t at the wrong position and the
        // drained order would be scrambled.
        let src = r#"type Task = { name: Str, prio: Int }
fun pqInsert(q: List[Task], t: Task) -> List[Task] {
    let lo = q.take_while(fn(x) { x.prio <= t.prio })
    let hi = q.drop_while(fn(x) { x.prio <= t.prio })
    [lo, [t], hi].flatten()
}
fun probe() -> Str {
    let seed: List[Task] = []
    let tasks = [Task(name: "c", prio: 3), Task(name: "a", prio: 1), Task(name: "e", prio: 5), Task(name: "b", prio: 2), Task(name: "d", prio: 4)]
    let q = tasks.fold(seed, fn(acc, t) { pqInsert(acc, t) })
    let order = q.map(fn(t) { t.name }).join("")
    let top = q.first().unwrap_or(Task(name: "none", prio: 0))
    "order={order}|top={top.name}@{top.prio}"
}
"#;
        assert_eq!(differential(src), "order=abcde|top=a@1");
    }

    #[test]
    fn diff_run_length_encode_decode_roundtrip() {
        // A certification lock (it320, milestone): run-length encoding + decoding round-trip. encode folds a
        // char list into a List[Run] (Run = {ch, n}) by GROUPING consecutive equal chars -- inspecting the
        // LAST accumulated run and either bumping its count (take all-but-last, push the updated Run) or
        // starting a new run; decode maps each run to ch.repeat(n) and joins. The round-trip decode(encode s)
        // == s is the correctness witness.
        //   "aaabbbcccd" -> [Run(a,3), Run(b,3), Run(c,3), Run(d,1)]  (summary "a3,b3,c3,d1")
        //   decode -> "aaabbbcccd"  => roundtrip true
        // Byte-identical on interp/KVM (native per the sweep). Confirms the fold reads acc.last() to decide
        // extend-vs-new, that extending a run replaces the tail element via `acc.take(acc.len()-1).push(r
        // with n: r.n+1)` (record update inside a fold), that a new char starts a fresh Run, and that decode
        // reconstructs the exact original via repeat+join. This is the classic string-compression RLE an AI
        // writes; a backend that mishandled the last-element inspection would fail to merge runs (emitting
        // a1,a1,a1... ) or the round-trip would break. Two gotchas documented by construction: the fold seed
        // needs a type annotation (`let init: List[Run] = []`) or the record-field access is K0232, and
        // `drop(len-1)` drops from the FRONT (keeping the last) -- `take(len-1)` is all-but-last.
        let src = r#"type Run = { ch: Str, n: Int }
fun encode(cs: List[Str]) -> List[Run] {
    let init: List[Run] = []
    cs.fold(init, fn(acc, c) {
        match acc.last() { Some(r) => {
                if r.ch == c { acc.take(acc.len() - 1).push(r with n: r.n + 1) }
                else { acc.push(Run(ch: c, n: 1)) }
            }
            None => acc.push(Run(ch: c, n: 1)) }
    })
}
fun decode(rs: List[Run]) -> Str {
    rs.map(fn(r) { r.ch.repeat(r.n) }).join("")
}
fun probe() -> Str {
    let s = "aaabbbcccd"
    let cs = s.chars()
    let runs = encode(cs)
    let summary = runs.map(fn(r) { "{r.ch}{r.n}" }).join(",")
    let back = decode(runs)
    "{summary}|roundtrip={back == s}"
}
"#;
        assert_eq!(differential(src), "a3,b3,c3,d1|roundtrip=true");
    }

    #[test]
    fn diff_matrix_transpose_and_matmul_nested_lists() {
        // A certification lock (it319): matrix operations on List[List[Int]] -- the nested-list matrix an AI
        // writes when it wants plain lists, NOT the builtin Tensor (it101-103/150/173/218 cover Tensor).
        // transpose extracts each column (map over rows, get(j)); matmul transposes b then dots each row of
        // a with each column of b via zip_with(*) + fold(+). Composed HOFs over a jagged-safe 2-D structure.
        //   transpose([[1,2],[3,4]]) = [[1,3],[2,4]]
        //   [[1,2],[3,4]] x [[5,6],[7,8]] = [[1*5+2*7, 1*6+2*8], [3*5+4*7, 3*6+4*8]] = [[19,22],[43,50]]
        // Byte-identical on interp/KVM (native per the sweep). Confirms transpose's column-extraction
        // (m.map(row -> row.get(j).unwrap_or(0)) over an index range), that matmul's nested map (outer over
        // a's rows, inner over b-transposed's columns) pairs the right row with the right column, and that
        // the per-cell dot product (zip_with multiply then fold-sum) computes each entry. The rangeN helper
        // builds the index list [0..ncols-1] because arange(n) returns a Tensor[Float], not List[Int] (so an
        // integer index range is hand-rolled). This is linear algebra on plain nested lists -- the matrix an
        // AI writes for a small transform, a rotation, or a layer without reaching for the tensor type; a
        // backend that mis-paired rows/columns in the nested map would transpose the product, and one that
        // mis-extracted a column would corrupt every cell.
        let src = r#"fun rangeN(n: Int) -> List[Int] {
    if n <= 0 { [] } else { [rangeN(n - 1), [n - 1]].flatten() }
}
fun col(m: List[List[Int]], j: Int) -> List[Int] {
    m.map(fn(row) { row.get(j).unwrap_or(0) })
}
fun transpose(m: List[List[Int]]) -> List[List[Int]] {
    let ncols = m.first().unwrap_or([]).len()
    rangeN(ncols).map(fn(j) { col(m, j) })
}
fun dotRow(row: List[Int], c: List[Int]) -> Int {
    row.zip_with(c, fn(a, b) { a * b }).fold(0, fn(s, x) { s + x })
}
fun matmul(a: List[List[Int]], b: List[List[Int]]) -> List[List[Int]] {
    let bt = transpose(b)
    a.map(fn(row) { bt.map(fn(bcol) { dotRow(row, bcol) }) })
}
fun probe() -> Str {
    let a = [[1, 2], [3, 4]]
    let b = [[5, 6], [7, 8]]
    let t = transpose(a)
    let p = matmul(a, b)
    "T={t}|P={p}"
}
"#;
        assert_eq!(differential(src), "T=[[1, 3], [2, 4]]|P=[[19, 22], [43, 50]]");
    }

    #[test]
    fn diff_memoized_fib_via_map() {
        // A certification lock (it317): MEMOIZED Fibonacci -- dynamic programming with a Map[Int,Int] memo
        // table threaded through the recursion. Prior Map locks fold INTO a Map (it292 tally, it300 buckets,
        // it307 pivot) or read an entity store (it286); this uses a Map as a MEMO whose updated copy must
        // thread through BOTH recursive calls so subproblems are computed once. Each call returns a record
        // {val, cache} bundling the answer AND the grown cache.
        //   fibMemo(n, cache): cache.get(n) Some(v) -> HIT (return v, cache unchanged);
        //     None -> MISS: n<2 -> (n, cache.insert(n,n)); else
        //       a = fibMemo(n-1, cache); b = fibMemo(n-2, a.cache);   // b threads a's updated cache
        //       r = a.val+b.val; return (r, b.cache.insert(n, r))
        //   fib8 = 21 ; fib12 = 144 ; cache after fib(12) holds fib(0)..fib(12) = 13 entries
        //   (depth kept to fib(12): deeper memoized recursion overflows the 2MB DEBUG test-thread stack;
        //    the release binary runs fib(20)=6765 fine -- this is a test-harness limit, not a language one)
        // Byte-identical on interp/KVM (native per the sweep). Confirms the Some/None memo hit/miss split,
        // that the cache THREADS through both recursive calls (b uses a.cache, not the original) so every
        // subproblem is memoized exactly once (cache size 13, not the exponential recompute count), that the
        // {val, cache} record carries the DP state functionally, and that base cases are cached too. This is
        // the memoize-an-exponential-recursion-into-linear an AI writes for DP -- the Map as a memo table
        // threaded as immutable state. A backend that didn't thread the cache through the second call would
        // recompute subtrees (still correct value but a wrong, larger cache-touch count) or, on a naive
        // build, blow up; one that mishandled the hit path would recompute a cached n. The cache size is the
        // witness that memoization actually happened.
        let src = r#"type Memo = { val: Int, cache: Map[Int, Int] }
fun fibMemo(n: Int, cache: Map[Int, Int]) -> Memo {
    match cache.get(n) { Some(v) => Memo(val: v, cache: cache)
        None => {
            if n < 2 { Memo(val: n, cache: cache.insert(n, n)) }
            else {
                let a = fibMemo(n - 1, cache)
                let b = fibMemo(n - 2, a.cache)
                let r = a.val + b.val
                Memo(val: r, cache: b.cache.insert(n, r))
            }
        } }
}
fun probe() -> Str {
    let m8 = fibMemo(8, Map())
    let m12 = fibMemo(12, Map())
    let hits = m12.cache.keys().len()
    "fib8={m8.val}|fib12={m12.val}|cachesize={hits}"
}
"#;
        assert_eq!(differential(src), "fib8=21|fib12=144|cachesize=13");
    }

    #[test]
    fn diff_graph_cycle_detection() {
        // A bug-hunt-50 lock (it316): GRAPH CYCLE DETECTION via DFS with an on-stack (recursion-path) set.
        // it315 does reachability with a single visited set; cycle detection needs a DIFFERENT set -- the
        // nodes currently ON the DFS recursion stack -- because a cycle is a BACK EDGE: a neighbor that is
        // already on the current path. Reaching a node twice is NOT a cycle (the diamond); reaching a node
        // that is still in-progress on the stack IS.
        //   hasCycleFrom(node, onStack): add node to onStack; for each neighbor n:
        //     if n is already on the stack -> back edge -> cycle (true); else recurse. .any short-circuits.
        //   dag = {1:[2,3], 2:[4], 3:[4], 4:[]}   -> false  (4 reached via both 2 and 3 but never on the
        //                                                     stack when checked -- a diamond, not a cycle)
        //   cyc = {1:[2], 2:[3], 3:[1]}           -> true   (3's neighbor 1 is on the stack {1,2,3})
        // Byte-identical on interp/KVM (native per the sweep). Confirms the on-stack Set threads down the
        // recursion path (add before recursing on neighbors), that a neighbor already on the stack is the
        // cycle signal (member test), that .any over neighbors short-circuits on the first back edge, and
        // -- crucially -- that a re-reached-but-not-on-stack node (4 in the diamond) is NOT flagged. This is
        // the DAG-check / dependency-cycle detector an AI writes for build graphs, module imports, or task
        // scheduling; a backend that used a plain visited set (like reachability) instead of an on-stack set
        // would falsely report the diamond DAG as cyclic, and one whose .any didn't short-circuit could miss
        // or mis-time the back-edge signal. it315's reachability can't distinguish a diamond from a cycle.
        let src = r#"fun member(s: Set[Int], x: Int) -> Bool {
    s.to_list().position(fn(y) { y == x }).is_some()
}
fun add(s: Set[Int], x: Int) -> Set[Int] {
    Set([[x], s.to_list()].flatten())
}
fun hasCycleFrom(adj: Map[Int, List[Int]], node: Int, onStack: Set[Int], done: Set[Int]) -> Bool {
    if member(done, node) { false }
    else {
        let stack2 = add(onStack, node)
        let neighbors = adj.get(node).unwrap_or([])
        neighbors.any(fn(n) {
            if member(stack2, n) { true }
            else { hasCycleFrom(adj, n, stack2, done) }
        })
    }
}
fun probe() -> Str {
    let dag = Map().insert(1, [2, 3]).insert(2, [4]).insert(3, [4]).insert(4, [])
    let cyc = Map().insert(1, [2]).insert(2, [3]).insert(3, [1])
    "dag={hasCycleFrom(dag, 1, Set([]), Set([]))}|cyc={hasCycleFrom(cyc, 1, Set([]), Set([]))}"
}
"#;
        assert_eq!(differential(src), "dag=false|cyc=true");
    }

    #[test]
    fn diff_graph_adjacency_dfs_reachability() {
        // A certification lock (it315): a GRAPH as an adjacency Map[Int, List[Int]] with recursive DFS
        // reachability threading a visited Set through a fold. Prior tree locks (it313/it314 BST, it296-312)
        // walk acyclic trees where every node has one parent; a graph has SHARED nodes (a diamond) and needs
        // a visited-set revisit guard so a node reached by two paths isn't reprocessed.
        //   adj = {1:[2,3], 2:[4], 3:[4], 4:[], 5:[6], 6:[]}   (two components; a 1->2->4 / 1->3->4 diamond)
        //   dfs(node): if node already in visited -> return visited unchanged (guard);
        //              else add node, then fold dfs over adj.get(node).unwrap_or([]) threading visited
        //   reach(1) = {1,2,3,4}  (node 4 reached via BOTH 2 and 3 but counted once), sorted [1,2,3,4]
        //   reach(5) = {5,6}      (disconnected from 1's component),                    sorted [5,6]
        // Byte-identical on interp/KVM (native per the sweep). Confirms the adjacency Map models out-edges
        // (get.unwrap_or([]) for sink nodes 4 and 6), that the visited Set THREADS through the neighbor fold
        // so each recursive call sees the accumulated set, that the revisit guard stops the diamond from
        // double-processing 4 (membership tested via to_list().position().is_some()), and that DFS from 1
        // never crosses into the {5,6} component. This is the graph traversal / reachability /
        // connected-component an AI writes constantly; a backend whose visited set didn't thread through the
        // fold would reprocess 4 (or loop forever on a cycle), and one that mishandled the sink's empty
        // neighbor list would crash. Distinct from every tree lock: shared nodes + explicit visited state.
        let src = r#"fun dfs(adj: Map[Int, List[Int]], node: Int, visited: Set[Int]) -> Set[Int] {
    if visited.to_list().position(fn(x) { x == node }).is_some() { visited }
    else {
        let seen = Set([[node], visited.to_list()].flatten())
        let neighbors = adj.get(node).unwrap_or([])
        neighbors.fold(seen, fn(acc, n) { dfs(adj, n, acc) })
    }
}
fun probe() -> Str {
    let adj = Map().insert(1, [2, 3]).insert(2, [4]).insert(3, [4]).insert(4, []).insert(5, [6]).insert(6, [])
    let reach1 = dfs(adj, 1, Set([])).to_list().sort_by(fn(x) { x })
    let reach5 = dfs(adj, 5, Set([])).to_list().sort_by(fn(x) { x })
    "from1={reach1}|from5={reach5}"
}
"#;
        assert_eq!(differential(src), "from1=[1, 2, 3, 4]|from5=[5, 6]");
    }

    #[test]
    fn diff_bst_contains_membership() {
        // A bug-hunt-49 lock (it314): BST MEMBERSHIP query -- the read/search counterpart to it313's
        // insert+inorder. contains navigates the search tree by a 3-way comparison (x == v -> true, x < v ->
        // recurse left, x > v -> recurse right), using the BST invariant to descend only ONE subtree per
        // node (pruning the other half), with Empty -> false the not-found base case. Composed with .all /
        // .any HOFs over lists of query keys, present and absent.
        //   t = fold(Empty, insert) over [5,3,8,1,4,7]
        //   [1,4,5,8].all(contains t)  -> true   (every present key is found)
        //   [2,6,9,0].any(contains t)  -> false  (no absent key is found)
        //   contains(t, 7) -> true ; contains(t, 99) -> false
        // Byte-identical on interp/KVM (native per the sweep). Confirms contains routes by comparison and
        // descends a single child per node (a present key deep in the tree like 7 is found; an absent key
        // like 99 bottoms out at Empty), that the not-found base returns false, and that .all over the
        // present keys is true while .any over the absent keys is false. This is the "is x in the set" /
        // search-tree lookup an AI writes as the query half of an ordered set; a backend that mis-routed the
        // comparison would miss a present key (present_all would go false) or spuriously match an absent one
        // (absent_any would go true). it313 builds and flattens to sorted order; this is the Bool-returning
        // navigate-by-compare search it never exercises.
        let src = r#"type BST = Empty | Node(v: Int, l: BST, r: BST)
fun insert(t: BST, x: Int) -> BST {
    match t { Empty => Node(v: x, l: Empty, r: Empty)
        Node(v, l, r) => {
            if x < v { Node(v: v, l: insert(l, x), r: r) }
            else { if x > v { Node(v: v, l: l, r: insert(r, x)) } else { Node(v: v, l: l, r: r) } }
        } }
}
fun contains(t: BST, x: Int) -> Bool {
    match t { Empty => false
        Node(v, l, r) => {
            if x == v { true }
            else { if x < v { contains(l, x) } else { contains(r, x) } }
        } }
}
fun probe() -> Str {
    let t = [5, 3, 8, 1, 4, 7].fold(Empty, fn(acc, x) { insert(acc, x) })
    let present = [1, 4, 5, 8].all(fn(x) { contains(t, x) })
    let absent = [2, 6, 9, 0].any(fn(x) { contains(t, x) })
    "present_all={present}|absent_any={absent}|has7={contains(t, 7)}|has99={contains(t, 99)}"
}
"#;
        assert_eq!(
            differential(src),
            "present_all=true|absent_any=false|has7=true|has99=false"
        );
    }

    #[test]
    fn diff_bst_insert_and_inorder() {
        // A certification lock (it313): a binary SEARCH tree -- recursive ordered insert maintaining the BST
        // invariant, built by fold, then inorder traversal producing sorted+deduped output. Prior tree
        // locks read (it296 sum/depth), rebuild 1:1 (it297 map), prune (it311), or test a predicate (it312);
        // none maintains an ORDERING invariant on insert. insert does a 3-way compare (x < v -> recurse
        // left, x > v -> recurse right, x == v -> no-op DEDUP) and functionally rebuilds the path; inorder
        // flattens [left, [v], right] so the BST reads out in sorted order.
        //   build([5,3,8,1,4,7,9,3]) folds insert from Empty; inorder -> [1,3,4,5,7,8,9]
        //     (the second 3 is dropped by the x == v no-op; the output is sorted AND deduplicated)
        // Byte-identical on interp/KVM (native per the sweep). Confirms insert routes each value to the
        // correct subtree by comparison and rebuilds only the touched path (the other subtree is shared
        // structurally), that Empty is the leaf-creating base case, that a duplicate key is a no-op (3
        // appears once), and that inorder's left-self-right flatten yields ascending order -- i.e. building
        // a search tree and reading it back sorts the input. This is the "sort via BST" / ordered-set an AI
        // writes as a data-structure exercise or an ordered index; a backend that mis-routed the comparison
        // would produce an unsorted inorder, and one that inserted duplicates would emit 3 twice.
        let src = r#"type BST = Empty | Node(v: Int, l: BST, r: BST)
fun insert(t: BST, x: Int) -> BST {
    match t { Empty => Node(v: x, l: Empty, r: Empty)
        Node(v, l, r) => {
            if x < v { Node(v: v, l: insert(l, x), r: r) }
            else { if x > v { Node(v: v, l: l, r: insert(r, x)) }
                else { Node(v: v, l: l, r: r) } }
        } }
}
fun inorder(t: BST) -> List[Int] {
    match t { Empty => []
        Node(v, l, r) => {
            let left = inorder(l)
            let right = inorder(r)
            [left, [v], right].flatten()
        } }
}
fun build(xs: List[Int]) -> BST {
    xs.fold(Empty, fn(acc, x) { insert(acc, x) })
}
fun probe() -> Str {
    let t = build([5, 3, 8, 1, 4, 7, 9, 3])
    let sorted = inorder(t)
    "{sorted}"
}
"#;
        assert_eq!(differential(src), "[1, 3, 4, 5, 7, 8, 9]");
    }

    #[test]
    fn diff_recursive_tree_balance_check() {
        // A bug-hunt-48 lock (it312): a recursive tree BALANCE predicate -- balanced() returns Bool, testing
        // the AVL invariant |height(l) - height(r)| <= 1 at EVERY node with `&&` short-circuit conjunction
        // over both subtrees. it296 computes a scalar depth-via-max; it311 prunes returning Option. This
        // pins a Bool-returning recursion that COMBINES a per-node height comparison with a recursive AND
        // over the children -- a node is balanced iff its two subtree heights differ by <=1 AND both
        // subtrees are themselves balanced.
        //   height(Leaf)=1; height(Branch)=1+max(height l, height r)
        //   balanced(Leaf)=true; balanced(Branch)= |h(l)-h(r)|<=1 && balanced(l) && balanced(r)
        //   bal  = Branch(Branch(Leaf 1, Leaf 2), Leaf 3)                     -> height 3, balanced true
        //   skew = Branch(Branch(Branch(Leaf 1, Leaf 2), Leaf 3), Leaf 4)     -> height 4, balanced FALSE
        //          (root: left subtree height 3, right height 1, |3-1|=2 > 1)
        // Byte-identical on interp/KVM (native per the sweep). Confirms height's `if hl > hr` max threads up
        // the tree, that the balance test fires the imbalance check at the root of skew (left height 3 vs
        // right 1) AND descends via `&&` so a deep imbalance anywhere fails the whole tree, and that Leaf is
        // the true base case. This is the "is my tree balanced" / AVL-or-red-black invariant check an AI
        // writes; a backend that only checked the root's immediate children (not recursing with &&) would
        // pass a tree with a deep imbalance, and one whose `&&` didn't short-circuit correctly would
        // mis-report. it296's depth is a single Int with no Bool combinator; it311's prune returns Option
        // and never conjuncts subtree predicates.
        let src = r#"type Tree = Leaf(v: Int) | Branch(l: Tree, r: Tree)
fun height(t: Tree) -> Int {
    match t { Leaf(v) => 1
        Branch(l, r) => {
            let hl = height(l)
            let hr = height(r)
            if hl > hr { 1 + hl } else { 1 + hr }
        } }
}
fun absDiff(a: Int, b: Int) -> Int {
    if a > b { a - b } else { b - a }
}
fun balanced(t: Tree) -> Bool {
    match t { Leaf(v) => true
        Branch(l, r) => {
            if absDiff(height(l), height(r)) > 1 { false }
            else { balanced(l) && balanced(r) }
        } }
}
fun probe() -> Str {
    let bal = Branch(l: Branch(l: Leaf(v: 1), r: Leaf(v: 2)), r: Leaf(v: 3))
    let skew = Branch(l: Branch(l: Branch(l: Leaf(v: 1), r: Leaf(v: 2)), r: Leaf(v: 3)), r: Leaf(v: 4))
    "h_bal={height(bal)}|bal={balanced(bal)}|h_skew={height(skew)}|skew={balanced(skew)}"
}
"#;
        assert_eq!(differential(src), "h_bal=3|bal=true|h_skew=4|skew=false");
    }

    #[test]
    fn diff_recursive_tree_prune_to_option() {
        // A certification lock (it311): a recursive tree PRUNE that returns Option[Tree] -- it drops leaves
        // failing a predicate and COLLAPSES branches when a subtree prunes to nothing, returning None if the
        // whole tree vanishes. it297's tree MAP always rebuilds every node 1:1; this conditionally REMOVES
        // structure: a Branch whose child pruned away becomes just the surviving child.
        //   prune(Leaf v)     = if v > 0 Some(Leaf v) else None
        //   prune(Branch l r) = merge(prune l, prune r):  None/None -> None,  Some/None -> Some(l),
        //                                                 None/Some -> Some(r), Some/Some -> Some(Branch)
        //   t      = Branch(Branch(Leaf 5, Leaf -3), Leaf 7)
        //            -> Branch(Leaf 5, Leaf 7)  (the -3 leaf drops; its Branch collapses to Leaf 5), sum 12
        //   allneg = Branch(Leaf -1, Leaf -2)   -> None (both leaves fail) -> "empty"
        // Byte-identical on interp/KVM (native per the sweep). Confirms the leaf predicate keeps/drops,
        // that the four-way Branch merge collapses a one-child branch to the surviving subtree (Branch(Leaf
        // 5, Leaf -3) becomes Leaf 5, NOT Branch(Leaf 5)), that a fully-pruned tree returns None, and that
        // the nested Option-matching threads through the recursion. sumT over the result witnesses the
        // surviving structure (5 + 7 = 12, the -3 gone). This is the filter/prune-a-tree an AI writes for
        // dead-node elimination, decision-tree pruning, or stripping empty nodes from an AST; a backend that
        // left an empty branch instead of collapsing it would keep a phantom node, and one that mishandled
        // the all-pruned case would return Some of an empty tree instead of None.
        let src = r#"type Tree = Leaf(v: Int) | Branch(l: Tree, r: Tree)
fun prune(t: Tree) -> Option[Tree] {
    match t { Leaf(v) => { if v > 0 { Some(Leaf(v: v)) } else { None } }
        Branch(l, r) => {
            let pl = prune(l)
            let pr = prune(r)
            match pl { None => pr
                Some(lt) => match pr { None => Some(lt)
                    Some(rt) => Some(Branch(l: lt, r: rt)) } } } }
}
fun sumT(t: Tree) -> Int {
    match t { Leaf(v) => v
        Branch(l, r) => sumT(l) + sumT(r) }
}
fun report(o: Option[Tree]) -> Str {
    match o { None => "empty"
        Some(t) => to_str(sumT(t)) }
}
fun probe() -> Str {
    let t = Branch(l: Branch(l: Leaf(v: 5), r: Leaf(v: 0 - 3)), r: Leaf(v: 7))
    let allneg = Branch(l: Leaf(v: 0 - 1), r: Leaf(v: 0 - 2))
    "{report(prune(t))}|{report(prune(allneg))}"
}
"#;
        assert_eq!(differential(src), "12|empty");
    }

    #[test]
    fn diff_recursive_adt_to_json_serialize_and_parse() {
        // A bug-hunt-47 lock (it310): recursive ADT-to-JSON SERIALIZATION -- a function that renders a Tree
        // ADT to a JSON string, then json_parse validates the result is well-formed. it309 pretty-prints to
        // S-expressions (no braces/JSON); it238 roundtrips a LITERAL JSON value through parse/stringify.
        // This pins ADT-driven JSON construction: the serializer recurses over Node/Leaf building object and
        // array syntax with `{{`/`}}` literal-brace escapes and `\"` quotes inside interpolated strings.
        //   toJson(Leaf v)     = {"leaf": v}
        //   toJson(Node l r)   = {"node": [toJson(l), toJson(r)]}
        //   t = Node(Leaf 1, Node(Leaf 2, Leaf 3))
        //     -> {"node": [{"leaf": 1}, {"node": [{"leaf": 2}, {"leaf": 3}]}]}
        //   json_parse(that) -> Ok  (well-formed)
        // Byte-identical on interp/KVM (native per the sweep). Confirms the recursive serializer emits
        // literal braces via `{{`/`}}` (not interpolation markers), that `\"` produces real quotes in the
        // JSON keys, that the two recursive results thread into the array in order, and that json_parse
        // accepts the machine-generated string (returns Ok, not an Err). This is the "serialize my data
        // structure to JSON" an AI writes for an API payload or a config dump; a backend that mis-handled
        // the brace escapes would emit malformed JSON that json_parse rejects, and one that lost recursion
        // order would swap the subtrees. (json_parse returns Result[Json, Str] -- matched here, not fed
        // straight to json_stringify, which is K0200.)
        let src = r##"type Tree = Leaf(v: Int) | Node(l: Tree, r: Tree)
fun toJson(t: Tree) -> Str {
    match t { Leaf(v) => "{{\"leaf\": {v}}}"
        Node(l, r) => {
            let ls = toJson(l)
            let rs = toJson(r)
            "{{\"node\": [{ls}, {rs}]}}"
        } }
}
fun checkParse(j: Str) -> Str {
    match json_parse(j) { Ok(v) => "ok"
        Err(e) => "err:{e}" }
}
fun probe() -> Str {
    let t = Node(l: Leaf(v: 1), r: Node(l: Leaf(v: 2), r: Leaf(v: 3)))
    let j = toJson(t)
    "{j}|parse={checkParse(j)}"
}
"##;
        assert_eq!(
            differential(src),
            r#"{"node": [{"leaf": 1}, {"node": [{"leaf": 2}, {"leaf": 3}]}]}|parse=ok"#
        );
    }

    #[test]
    fn diff_adt_pretty_printer_sexpr() {
        // A certification lock (it309): a mutual-recursive ADT PRETTY-PRINTER -- rendering an S-expression
        // tree back to a Str. it308's mutual recursion computes a scalar SIZE; this renders to text with
        // separator and delimiter logic. show walks Sx variants (Atom -> name, Num -> to_str, Lst ->
        // parenthesized), and its Lst arm wraps showList's output in parens; showList walks the List[Sx] via
        // first/drop and space-JOINS each element's rendering with no leading/trailing space -- the two
        // functions recurse through each other.
        //   e     = Lst([Atom "add", Num 1, Lst([Atom "mul", Num 2, Num 3])])  ->  "(add 1 (mul 2 3))"
        //   empty = Lst([])                                                    ->  "()"
        // Byte-identical on interp/KVM (native per the sweep). Confirms each variant renders by its own arm,
        // that show<->showList mutual recursion parenthesizes nested Lists to arbitrary depth (the inner
        // (mul 2 3) sits inside the outer list), that showList space-joins WITHOUT a trailing space (it
        // checks the recursive tail for "" and omits the separator on the last element), and that an EMPTY
        // Lst renders as "()" (showList([]) = ""). This is the AST / config / S-expression pretty-printer an
        // AI writes to serialize a value tree back to source; a backend that left a trailing space would
        // emit "(add 1 (mul 2 3) )", and one that lost the mutual linkage would fail to parenthesize the
        // nested list. it308 computes a number and never builds a string with separators; it302's report is
        // over FLAT records with no recursion.
        let src = r#"type Sx = Atom(name: Str) | Num(v: Int) | Lst(items: List[Sx])
fun show(s: Sx) -> Str {
    match s { Atom(name) => name
        Num(v) => to_str(v)
        Lst(items) => "({showList(items)})" }
}
fun showList(xs: List[Sx]) -> Str {
    match xs.first() { None => ""
        Some(h) => {
            let rest = xs.drop(1)
            let tail = showList(rest)
            if tail == "" { show(h) } else { "{show(h)} {tail}" }
        } }
}
fun probe() -> Str {
    let e = Lst(items: [Atom(name: "add"), Num(v: 1), Lst(items: [Atom(name: "mul"), Num(v: 2), Num(v: 3)])])
    let empty = Lst(items: [])
    "{show(e)}|{show(empty)}"
}
"#;
        assert_eq!(differential(src), "(add 1 (mul 2 3))|()");
    }

    #[test]
    fn diff_mutual_recursion_over_adt_with_list_variant() {
        // A bug-hunt-46 lock (it308): MUTUAL recursion over an ADT whose variant holds a List of itself.
        // Prior mutual-recursion locks (it139/205/219/227) are even/odd style over Int; single-function ADT
        // recursion is it296 (binary tree) / it298 (expr). This pins the container-ADT shape: sizeN walks
        // Node variants and its Many arm delegates to sizeList, while sizeList walks the List[Node] via
        // first/drop (the it303 idiom) and calls back into sizeN on each element -- the two functions
        // recurse THROUGH each other.
        //   Node = Leaf(v: Int) | Pair(a: Node, b: Node) | Many(items: List[Node])
        //   t  = Many([Leaf 1, Pair(Leaf 2, Leaf 3), Many([Leaf 4, Leaf 5])])
        //        sizeN = 1 + 2 + 2 = 5  (Many -> sizeList -> sizeN per child, nested Many recurses again)
        //   t2 = Pair(Many([]), Leaf 9)
        //        sizeN = 0 + 1 = 1      (empty Many -> sizeList([]) = 0 base case, then the Leaf)
        // Byte-identical on interp/KVM (native per the sweep). Confirms the Many arm hands a List[Node] to
        // sizeList, that sizeList's first()/drop(1) recursion calls sizeN on the head and terminates on
        // None, that an EMPTY Many bottoms out at sizeList([]) = 0, and that a nested Many inside the list
        // recurses back through both functions to its Leaves. This is the JSON-like value tree / AST with a
        // variadic node / filesystem tree an AI models constantly -- a variant carrying a list of children
        // needs exactly this fn<->fn dispatch. A backend that lost the mutual linkage would fail to descend
        // into Many's children, undercounting t as 3 (or crashing on the list-valued field).
        let src = r#"type Node = Leaf(v: Int) | Pair(a: Node, b: Node) | Many(items: List[Node])
fun sizeN(n: Node) -> Int {
    match n { Leaf(v) => 1
        Pair(a, b) => sizeN(a) + sizeN(b)
        Many(items) => sizeList(items) }
}
fun sizeList(xs: List[Node]) -> Int {
    match xs.first() { None => 0
        Some(h) => sizeN(h) + sizeList(xs.drop(1)) }
}
fun probe() -> Str {
    let t = Many(items: [Leaf(v: 1), Pair(a: Leaf(v: 2), b: Leaf(v: 3)), Many(items: [Leaf(v: 4), Leaf(v: 5)])])
    let t2 = Pair(a: Many(items: []), b: Leaf(v: 9))
    "{sizeN(t)}|{sizeN(t2)}"
}
"#;
        assert_eq!(differential(src), "5|1");
    }

    #[test]
    fn diff_fold_into_nested_map_of_maps_pivot() {
        // A certification lock (it307): fold records into a NESTED Map-of-Maps -- a 2-level pivot /
        // cross-tabulation (region x product). it300 folds into a Map of LISTS (one level); it292 into a
        // Map of Ints (one level); this pins TWO levels of nesting where the accumulator is
        // Map[Str, Map[Str, Int]], built with get-or-Map() at the OUTER level and get-or-0 at the inner.
        //   sales = [west/a/10, east/a/20, west/b/5, west/a/3, east/b/7]
        //   fold(Map(), (acc, s) ->
        //     inner = acc.get(s.region).unwrap_or(Map())         // fresh inner Map on a region's 1st sighting
        //     prev  = inner.get(s.product).unwrap_or(0)          // tally within (region, product)
        //     acc.insert(s.region, inner.insert(s.product, prev + s.amt)))
        //   nested = {west: {a: 13, b: 5}, east: {a: 20, b: 7}}, keys() = [west, east]
        // Byte-identical on interp/KVM (native per the sweep). Confirms the outer get-or-Map() default
        // creates a fresh inner map per new region, the inner get-or-0 accumulates a cell, the
        // insert(region, inner.insert(product, ..)) functionally updates BOTH levels, that west/a
        // accumulates across two NON-adjacent sightings (10 then 3 = 13, not last-wins 3), and that the
        // outer region keys stay in first-seen order (west before east). This is the 2-D group-by / pivot
        // table an AI writes to cross-tabulate sales by region and product, events by day and type, or
        // metrics by host and metric-name. A backend that dropped the get-or-Map() default would panic on
        // each region's first row, and one that overwrote instead of accumulating the inner cell would
        // report west/a = 3.
        // (Inner lookups are bound to plain lets before interpolation -- nested quotes inside {..} trip
        // K0007, a gotcha this test sidesteps by construction.)
        let src = r#"type Sale = { region: Str, product: Str, amt: Int }
fun probe() -> Str {
    let sales = [Sale(region: "west", product: "a", amt: 10), Sale(region: "east", product: "a", amt: 20), Sale(region: "west", product: "b", amt: 5), Sale(region: "west", product: "a", amt: 3), Sale(region: "east", product: "b", amt: 7)]
    let nested = sales.fold(Map(), fn(acc, s) {
        let inner = acc.get(s.region).unwrap_or(Map())
        let prev = inner.get(s.product).unwrap_or(0)
        acc.insert(s.region, inner.insert(s.product, prev + s.amt))
    })
    let west = nested.get("west").unwrap_or(Map())
    let east = nested.get("east").unwrap_or(Map())
    let wa = west.get("a").unwrap_or(0)
    let wb = west.get("b").unwrap_or(0)
    let ea = east.get("a").unwrap_or(0)
    let eb = east.get("b").unwrap_or(0)
    "regions={nested.keys()}|west.a={wa}|west.b={wb}|east.a={ea}|east.b={eb}"
}
"#;
        assert_eq!(
            differential(src),
            r#"regions=["west", "east"]|west.a=13|west.b=5|east.a=20|east.b=7"#
        );
    }

    #[test]
    fn diff_nested_option_flatten_via_and_then() {
        // A bug-hunt-45 lock (it306): the Option-monad JOIN -- flattening Option[Option] and chaining
        // and_then through a fallible lookup. it290 chains map/filter/unwrap_or over records; this pins the
        // DOUBLE-Option case an AI hits when a lookup returns an Option and its value is itself optional
        // (Map.get of an Option-valued entry, a config-of-configs).
        //   deref(o) = o.and_then(lookup); lookup(k) = if k > 0 Some(k*10) else None
        //     deref(Some(3))  -> lookup(3)  = Some(30) -> unwrap_or(-1) = 30
        //     deref(Some(-1)) -> lookup(-1) = None     -> unwrap_or(-1) = -1  (inner lookup fails)
        //     deref(None)     -> None (closure never runs) -> unwrap_or(-1) = -1
        //   flatten via and_then(identity):
        //     Some(Some(5)).and_then(id) = Some(5) -> unwrap_or(-9) = 5
        //     Some(None).and_then(id)    = None    -> unwrap_or(-9) = -9
        // Byte-identical on interp/KVM (native per the sweep). Confirms and_then flattens exactly one level
        // (the closure returns an Option and the result is NOT Some(Some(..))), that None short-circuits at
        // BOTH positions -- an outer None never invokes the closure (deref(None)), and an inner-lookup None
        // propagates (deref(Some(-1))) -- and that the join idiom Some(Some x).and_then(id) collapses to
        // Some x while Some(None).and_then(id) collapses to None. This is the Option monad an AI leans on
        // for chained optional lookups; a backend that returned Some(Some 5) (no flatten) or ran the
        // closure on None would break the chain.
        let src = r#"fun lookup(k: Int) -> Option[Int] {
    if k > 0 { Some(k * 10) } else { None }
}
fun deref(o: Option[Int]) -> Option[Int] {
    o.and_then(fn(v) { lookup(v) })
}
fun probe() -> Str {
    let a = deref(Some(3))
    let b = deref(Some(0 - 1))
    let c = deref(None)
    let d = Some(Some(5)).and_then(fn(inner) { inner })
    let e = Some(None).and_then(fn(inner) { inner })
    "{a.unwrap_or(0 - 1)}|{b.unwrap_or(0 - 1)}|{c.unwrap_or(0 - 1)}|{d.unwrap_or(0 - 9)}|{e.unwrap_or(0 - 9)}"
}
"#;
        assert_eq!(differential(src), "30|-1|-1|5|-9");
    }

    #[test]
    fn diff_sort_records_by_two_keys_composite() {
        // A certification lock (it305): a MULTI-KEY sort -- "ORDER BY dept ASC, salary DESC" encoded as a
        // single composite Int key. it288 sorts by a single negated key (one criterion, descending); this
        // pins TWO criteria in one key: a primary (dept, ascending) scaled past the secondary's range so it
        // dominates, minus the secondary (salary) so it sorts descending WITHIN a dept. Plus stability on a
        // full tie.
        //   key(e) = e.dept*1000 - e.salary
        //     b(d1,s90)=910  d(d1,s70)=930  c(d2,s80)=1920  e(d2,s80)=1920  a(d2,s50)=1950
        //   sort_by ascending+stable -> b, d, c, e, a
        //     dept 1 before dept 2 (primary asc); within a dept higher salary first (b90 before d70);
        //     c and e have an IDENTICAL composite key (both d2/s80) -> source order preserved (c before e).
        // Byte-identical on interp/KVM (native per the sweep). Confirms sort_by is ascending and STABLE,
        // that a composite key with a dominating multiplier orders the primary key first and the scaled-
        // then-subtracted secondary descending within each group, and that two records colliding on the
        // full composite key keep their original relative order (c before e, not e before c). This is the
        // multi-column ORDER BY an AI writes for any table/leaderboard/ranking; a backend with an unstable
        // sort would flip c/e, and one that mis-scaled the key would interleave the depts.
        let src = r#"type Emp = { dept: Int, salary: Int, name: Str }
fun probe() -> Str {
    let emps = [Emp(dept: 2, salary: 50, name: "a"), Emp(dept: 1, salary: 90, name: "b"), Emp(dept: 2, salary: 80, name: "c"), Emp(dept: 1, salary: 70, name: "d"), Emp(dept: 2, salary: 80, name: "e")]
    let sorted = emps.sort_by(fn(e) { e.dept * 1000 - e.salary })
    sorted.map(fn(e) { e.name }).join(",")
}
"#;
        assert_eq!(differential(src), "b,d,c,e,a");
    }

    #[test]
    fn diff_recursive_list_via_first_drop_and_fold_reverse() {
        // A bug-hunt-44 lock (it303): STRUCTURAL recursion over a List. KUPL has no cons-pattern
        // (`[h, ..t]` is K0113), so the idiom is to match `xs.first()` -> None (base) / Some(h) (recurse
        // on `xs.drop(1)`). Prior recursion locks walk ADTs (it296 tree, it298 expr); this pins recursion
        // driven by list head/tail via first()/drop(), plus a fold-based reverse that PREPENDS each element
        // by flattening [[x], acc] -- the accumulator-prepend reversal an AI writes constantly.
        //   sumR([1..5]) = 15, lenR([1..5]) = 5   (recurse: Some(h) => h(or 1) + f(drop 1); None => 0)
        //   revF([1..5]) = [5,4,3,2,1]            (fold([], (acc,x) -> [[x], acc].flatten()))
        //   empty list: sumR/lenR = 0, revF = []  (base cases fire on first() == None)
        // Byte-identical on interp/KVM (native per the sweep). Confirms first() returns None on [] and
        // Some(head) otherwise across all engines, that drop(1) yields the tail so the recursion terminates,
        // that a fold seeded with [] threads a growing list while [[x], acc].flatten() prepends (giving
        // reversal, not append), and that all three empty-list base cases agree. This is the hand-rolled
        // list-recursion + reverse an AI reaches for when it wants explicit control instead of a builtin; a
        // backend where first()/drop() disagreed on the boundary would loop forever or drop an element, and
        // one that flattened [[x], acc] in the wrong order would append instead of reverse.
        let src = r#"fun sumR(xs: List[Int]) -> Int {
    match xs.first() { None => 0
        Some(h) => h + sumR(xs.drop(1)) }
}
fun lenR(xs: List[Int]) -> Int {
    match xs.first() { None => 0
        Some(h) => 1 + lenR(xs.drop(1)) }
}
fun revF(xs: List[Int]) -> List[Int] {
    xs.fold([], fn(acc, x) { [[x], acc].flatten() })
}
fun probe() -> Str {
    let xs = [1, 2, 3, 4, 5]
    let empty: List[Int] = []
    "{sumR(xs)}|{lenR(xs)}|{revF(xs)}|{sumR(empty)}|{lenR(empty)}|{revF(empty)}"
}
"#;
        assert_eq!(differential(src), "15|5|[5, 4, 3, 2, 1]|0|0|[]");
    }

    #[test]
    fn diff_tabular_report_from_records_header_body_footer() {
        // A certification lock (it302): a multi-line tabular REPORT from records -- header + column-aligned
        // rows + grand-total footer, assembled declaratively. it240 builds a report by interpolating the
        // accumulator back into itself in a LOOP (imperative, no alignment, no footer-fold); this pins the
        // map->join table an AI actually generates: map each record to a pad-aligned row string, join("\n")
        // the body, fold a SEPARATE grand total, and compose header\nbody\nfooter.
        //   rows = [apple q3 p50, pear q2 p70, kiwi q5 p30]
        //   each row: name.pad_right(10) + qty.pad_left(3) + total.pad_left(5); total = qty*price
        //   grand = fold(0, +qty*price) = 150+140+150 = 440
        // Byte-identical on interp/KVM (native per the sweep). Confirms map-over-records yields the row
        // strings in order, that pad_right/pad_left column alignment lands identically on all engines
        // (fixed-width columns are where a stringify-width bug would show), that join("\n") assembles the
        // body without a trailing separator, and that a fold over the SAME rows produces the grand total
        // independently of the row mapping. The row formatter is a helper fn (interp exprs stay simple --
        // nested quotes inside {..} would trip K0007), so this also exercises map(fn-by-name). This is the
        // invoice / receipt / summary-table an AI emits for a CLI or report; a backend that mis-padded a
        // column or left a trailing newline in the join would desync the whole table.
        let src = r#"type Row = { name: Str, qty: Int, price: Int }
fun fmtRow(r: Row) -> Str {
    let sp = " "
    let total = r.qty * r.price
    let nm = r.name.pad_right(10, sp)
    let q = to_str(r.qty).pad_left(3, sp)
    let t = to_str(total).pad_left(5, sp)
    "{nm} {q}  {t}"
}
fun probe() -> Str {
    let rows = [Row(name: "apple", qty: 3, price: 50), Row(name: "pear", qty: 2, price: 70), Row(name: "kiwi", qty: 5, price: 30)]
    let header = "ITEM       QTY  TOTAL"
    let body = rows.map(fmtRow).join("\n")
    let grand = rows.fold(0, fn(acc, r) { acc + r.qty * r.price })
    let footer = "TOTAL: {grand}"
    "{header}\n{body}\n{footer}"
}
"#;
        assert_eq!(
            differential(src),
            "ITEM       QTY  TOTAL\napple        3    150\npear         2    140\nkiwi         5    150\nTOTAL: 440"
        );
    }

    #[test]
    fn diff_adt_variant_with_record_typed_field() {
        // A bug-hunt-43 lock (it301): an ADT whose variants carry RECORD-typed fields (not scalars).
        // Prior REC-ADT locks (it296 Leaf(v: Int), it298 Num(v: Int)) wrap Ints; this pins a tagged union
        // of structs -- a Shape ADT where Circle wraps a Pt center, Rect wraps two Pts (tl/br), and Dot
        // wraps a Pt. A match binds the record-typed field and the arm body reads its NESTED fields.
        //   Circle(center=Pt(2,3), r=5) -> area 3*r*r = 75, originX = c.x = 2
        //   Rect(tl=Pt(1,1), br=Pt(4,6)) -> area (br.x-tl.x)*(br.y-tl.y) = 3*5 = 15, originX = tl.x = 1
        //   Dot(at=Pt(9,9))             -> area 0,                                    originX = at.x = 9
        // Byte-identical on interp/KVM (native per the sweep). Confirms a constructor field can be a full
        // record, that the match arm binds that record and reads its fields (c.x, and br.x-tl.x combining
        // two bound records' fields), and that all three engines lay out and access the nested Pt
        // identically. This is the geometry/shape tagged-union an AI writes constantly -- variants wrapping
        // structs (an AST node holding a Span record, an event holding a Payload). A backend that mis-laid
        // a record-in-variant would misread br.x/tl.x and get the Rect area or origin wrong while the
        // scalar-free Dot still looked fine.
        let src = r#"type Pt = { x: Int, y: Int }
type Shape = Circle(center: Pt, r: Int) | Rect(tl: Pt, br: Pt) | Dot(at: Pt)
fun area(s: Shape) -> Int {
    match s { Circle(c, r) => 3 * r * r
        Rect(tl, br) => (br.x - tl.x) * (br.y - tl.y)
        Dot(at) => 0 }
}
fun originX(s: Shape) -> Int {
    match s { Circle(c, r) => c.x
        Rect(tl, br) => tl.x
        Dot(at) => at.x }
}
fun probe() -> Str {
    let c = Circle(center: Pt(x: 2, y: 3), r: 5)
    let rc = Rect(tl: Pt(x: 1, y: 1), br: Pt(x: 4, y: 6))
    let d = Dot(at: Pt(x: 9, y: 9))
    "{area(c)}|{area(rc)}|{area(d)}|ox={originX(c)},{originX(rc)},{originX(d)}"
}
"#;
        assert_eq!(differential(src), "75|15|0|ox=2,1,9");
    }

    #[test]
    fn diff_fold_records_into_map_of_lists_bucketing() {
        // A certification lock (it300, milestone): fold records into a Map-of-LISTS -- bucket each item
        // into a per-key list. it292 folds into a Map of Ints (get-or-0 + sum); this pins the
        // group-into-lists variant where the accumulator VALUE is a List that grows via push and
        // get().unwrap_or([]) supplies the empty-list default for a key's first sighting. This is the
        // hand-rolled group_by returning Map[Str, List[Str]] (categorize into buckets), the shape an AI
        // writes when it needs the grouped members, not just counts.
        //   items = [apple/fruit, carrot/veg, banana/fruit, pea/veg, cherry/fruit]
        //   fold(Map(), (acc, it) -> acc.insert(it.cat, acc.get(it.cat).unwrap_or([]).push(it.name)))
        //     grouped == {"fruit": ["apple","banana","cherry"], "veg": ["carrot","pea"]}
        //     keys()  == ["fruit", "veg"]   (first-seen category order)
        // Byte-identical on interp/KVM (native per the sweep). Confirms an empty Map() seed threads a
        // List-valued accumulator, that get().unwrap_or([]) starts a fresh bucket on first sighting, that
        // push appends within a bucket in encounter order (apple before banana before cherry), and that
        // re-inserting an existing key keeps its position while replacing its list with the grown one.
        // This is the categorize/bucket-by-field an AI writes for grouping records by type, files by
        // extension, or events by day. A backend that dropped the get-or-empty default would panic on the
        // first item of each category, and one that reordered a key on re-insert would list veg before
        // fruit.
        let src = r#"type Item = { name: Str, cat: Str }
fun probe() -> Str {
    let items = [Item(name: "apple", cat: "fruit"), Item(name: "carrot", cat: "veg"), Item(name: "banana", cat: "fruit"), Item(name: "pea", cat: "veg"), Item(name: "cherry", cat: "fruit")]
    let grouped = items.fold(Map(), fn(acc, it) {
        let prev = acc.get(it.cat).unwrap_or([])
        acc.insert(it.cat, prev.push(it.name))
    })
    let fruits = grouped.get("fruit").unwrap_or([])
    let veg = grouped.get("veg").unwrap_or([])
    "{grouped.keys()}|fruit={fruits}|veg={veg}"
}
"#;
        assert_eq!(
            differential(src),
            r#"["fruit", "veg"]|fruit=["apple", "banana", "cherry"]|veg=["carrot", "pea"]"#
        );
    }

    #[test]
    fn diff_recursive_expr_evaluator_returning_result() {
        // A bug-hunt-42 lock (it299): a FALLIBLE recursive AST evaluator -- each node's eval returns
        // Result[Int, Str], and_then/map thread the recursive results, and Div returns Err on a zero
        // divisor. it298 evaluates a total expr to an Int; this pins error propagation through recursion:
        // a failing sub-expression's Err bubbles up and short-circuits the enclosing node.
        //   e1 = Add(Num 10, Div(Num 20, Num 4))        -> Ok(10 + 5) = Ok(15)
        //   e2 = Div(Num 8, Add(Num 3, Num -3))         -> divisor Add(3,-3) COMPUTES to 0 -> Err("div by zero")
        //   e3 = Add(Div(Num 9, Num 0), Num 1)          -> inner Div errs -> and_then short-circuits the Add
        // Byte-identical on interp/KVM (native per the sweep). Confirms Result threads through a recursive
        // evaluator (each Add/Div sequences its two sub-evals with and_then/map), that the divisor subtree
        // is fully evaluated before the zero check (e2's zero is computed, not a literal), and that an Err
        // produced at arbitrary depth propagates to the top so the enclosing Add in e3 never runs its map.
        // This is the fallible interpreter an AI writes for a spreadsheet formula engine or a calculator
        // that reports errors instead of crashing; a backend that short-circuited on a literal-zero check
        // only, or that let the Add in e3 complete despite the inner Err, would return a wrong Ok.
        let src = r#"type Expr = Num(v: Int) | Add(l: Expr, r: Expr) | Div(l: Expr, r: Expr)
fun eval(e: Expr) -> Result[Int, Str] {
    match e { Num(v) => Ok(v)
        Add(l, r) => eval(l).and_then(fn(a) { eval(r).map(fn(b) { a + b }) })
        Div(l, r) => eval(l).and_then(fn(a) { eval(r).and_then(fn(b) {
            if b == 0 { Err("div by zero") } else { Ok(a / b) } }) }) }
}
fun outcome(r: Result[Int, Str]) -> Str {
    match r { Ok(v) => "ok:{v}"
        Err(e) => "err:{e}" }
}
fun probe() -> Str {
    let e1 = Add(l: Num(v: 10), r: Div(l: Num(v: 20), r: Num(v: 4)))
    let e2 = Div(l: Num(v: 8), r: Add(l: Num(v: 3), r: Num(v: 0 - 3)))
    let e3 = Add(l: Div(l: Num(v: 9), r: Num(v: 0)), r: Num(v: 1))
    "{outcome(eval(e1))}|{outcome(eval(e2))}|{outcome(eval(e3))}"
}
"#;
        assert_eq!(differential(src), "ok:15|err:div by zero|err:div by zero");
    }

    #[test]
    fn diff_recursive_expr_evaluator_four_variants() {
        // A certification lock (it298): a recursive ADT interpreter over a FOUR-variant expression type
        // with mixed arities -- the canonical tree-walking eval. it296 traverses a 2-variant Leaf/Branch
        // tree; this pins a richer ADT (Num holds an Int, Add/Mul hold two sub-Exprs, Neg holds one) with
        // a single match dispatching all four arms recursively, so operator precedence falls out of the
        // tree shape rather than any parsing.
        //   e1 = Add(Num 3, Mul(Num 4, Num 5))            = 3 + (4*5)      = 23
        //   e2 = Mul(Add(Num 2, Num 3), Neg(Num 6))       = (2+3) * (-6)   = -30
        //   e3 = Neg(Add(Num 10, Neg(Num 4)))             = -(10 + (-4))   = -6
        // Byte-identical on interp/KVM (native per the sweep). Confirms a four-constructor ADT with
        // per-variant arities (one nullary-payload, two binary, one unary) evaluates recursively, that
        // Neg's `0 - eval(e)` negation composes with nested Neg (e3's inner -4 flips back inside the sum),
        // and that Add/Mul thread their two recursive results in the right order. This is the calculator /
        // formula-engine / mini-language interpreter an AI writes constantly; a backend that mis-bound a
        // binary constructor's second field or mishandled the unary Neg would miscompute e2 or e3 while
        // the flat e1 looked fine.
        let src = r#"type Expr = Num(v: Int) | Add(l: Expr, r: Expr) | Mul(l: Expr, r: Expr) | Neg(e: Expr)
fun eval(e: Expr) -> Int {
    match e { Num(v) => v
        Add(l, r) => eval(l) + eval(r)
        Mul(l, r) => eval(l) * eval(r)
        Neg(e2) => 0 - eval(e2) }
}
fun probe() -> Str {
    let e1 = Add(l: Num(v: 3), r: Mul(l: Num(v: 4), r: Num(v: 5)))
    let e2 = Mul(l: Add(l: Num(v: 2), r: Num(v: 3)), r: Neg(e: Num(v: 6)))
    let e3 = Neg(e: Add(l: Num(v: 10), r: Neg(e: Num(v: 4))))
    "{eval(e1)}|{eval(e2)}|{eval(e3)}"
}
"#;
        assert_eq!(differential(src), "23|-30|-6");
    }

    #[test]
    fn diff_recursive_tree_map_with_higher_order_fn() {
        // A bug-hunt-41 lock (it297): a recursive tree MAP that REBUILDS the ADT, driven by a
        // higher-order fn parameter. it296 traverses a tree down to a scalar (sum/count/depth); this
        // pins the functor-map shape -- mapT(t, f) recurses returning a NEW Tree with f applied at every
        // Leaf and the Branch structure preserved, and f is passed in as a `fn(Int) -> Int` argument.
        //   t = Branch(Leaf 3, Branch(Leaf 5, Leaf 2))    (sum 10)
        //   mapT(t, x -> x*2)  rebuilds Branch(Leaf 6, Branch(Leaf 10, Leaf 4))   -> sum 20
        //   mapT(t, x -> x+10) rebuilds Branch(Leaf 13, Branch(Leaf 15, Leaf 12)) -> sum 40
        // Byte-identical on interp/KVM (native per the sweep). Confirms a recursive function can take a
        // function-typed parameter and thread it through both recursive calls, that the closure fires
        // once per leaf (3 leaves -> +6 doubled, +30 plus-ten over the original sum of 10), and that the
        // rebuilt tree keeps the same Branch/Leaf shape so a follow-up sumT reads it back correctly. This
        // is the map-over-a-recursive-structure an AI writes to rewrite an AST, rescale a scene graph,
        // or transform a nested config. A backend that dropped the fn parameter across the recursion, or
        // rebuilt the branches in the wrong shape, would return the original sum or a mis-structured tree.
        let src = r#"type Tree = Leaf(v: Int) | Branch(l: Tree, r: Tree)
fun mapT(t: Tree, f: fn(Int) -> Int) -> Tree {
    match t { Leaf(v) => Leaf(v: f(v))
        Branch(l, r) => Branch(l: mapT(l, f), r: mapT(r, f)) }
}
fun sumT(t: Tree) -> Int {
    match t { Leaf(v) => v
        Branch(l, r) => sumT(l) + sumT(r) }
}
fun probe() -> Str {
    let t = Branch(l: Leaf(v: 3), r: Branch(l: Leaf(v: 5), r: Leaf(v: 2)))
    let doubled = mapT(t, fn(x) { x * 2 })
    let plus10 = mapT(t, fn(x) { x + 10 })
    "{sumT(t)}|doubled={sumT(doubled)}|plus10={sumT(plus10)}"
}
"#;
        assert_eq!(differential(src), "10|doubled=20|plus10=40");
    }

    #[test]
    fn diff_recursive_binary_tree_traversals() {
        // A certification lock (it296): three independent recursive traversals over a BINARY tree ADT
        // -- sum, leaf-count, and depth -- each pattern-matching Leaf/Branch and recursing on both
        // children. it166 locks a single shallow tree sum; it245 locks a UNARY-constructor depth; this
        // pins the binary case where depth combines an if-expression with two recursive calls
        // (1 + max(depth(l), depth(r))), the shape that actually recurses down both subtrees per node.
        //   t = Branch(Branch(Leaf 3, Leaf 5), Branch(Leaf 2, Branch(Leaf 7, Leaf 1)))
        //   sumT        = 3+5+2+7+1 = 18
        //   countLeaves = 5
        //   depth       = 4   (deepest path root -> Branch -> Branch(2,..) -> Branch(7,1) -> Leaf)
        // Byte-identical on interp/KVM (native per the sweep). Confirms a self-referential ADT
        // (Branch(l: Tree, r: Tree)) constructs and destructures to arbitrary depth, that three
        // distinct recursive functions over the same value agree across engines, and that depth's
        // 1 + max(recurse-left, recurse-right) picks the taller subtree (right side here, which holds
        // the extra nesting). This is the canonical walk-a-tree an AI writes for ASTs, file
        // hierarchies, or decision trees. A backend with a shallow recursion cap or that mis-bound the
        // second child in Branch(l, r) would under-count or mis-depth the asymmetric right subtree.
        let src = r#"type Tree = Leaf(v: Int) | Branch(l: Tree, r: Tree)
fun sumT(t: Tree) -> Int {
    match t { Leaf(v) => v
        Branch(l, r) => sumT(l) + sumT(r) }
}
fun countLeaves(t: Tree) -> Int {
    match t { Leaf(v) => 1
        Branch(l, r) => countLeaves(l) + countLeaves(r) }
}
fun depth(t: Tree) -> Int {
    match t { Leaf(v) => 1
        Branch(l, r) => 1 + (if depth(l) > depth(r) { depth(l) } else { depth(r) }) }
}
fun probe() -> Str {
    let t = Branch(l: Branch(l: Leaf(v: 3), r: Leaf(v: 5)), r: Branch(l: Leaf(v: 2), r: Branch(l: Leaf(v: 7), r: Leaf(v: 1))))
    "{sumT(t)}|leaves={countLeaves(t)}|depth={depth(t)}"
}
"#;
        assert_eq!(differential(src), "18|leaves=5|depth=4");
    }

    #[test]
    fn diff_map_fold_record_values_into_str_report() {
        // A bug-hunt-40 lock (it295): Map.fold's 3-arg (acc, k, v) form building a STRING report over a
        // RECORD-valued map, computing a derived stat per entry. it277 folds a scalar-valued map into a
        // record; the older Map.fold-to-String locks use scalar values. This pins the "render a report
        // line per entry from a map of stats records" idiom -- read the key AND a couple of the value
        // record's fields, compute a percentage, and join with the first-entry-has-no-separator trick.
        //   m = {"api": Stat(90,10), "db": Stat(40,60), "cache": Stat(99,1)}
        //   fold("", (acc, k, v) -> line "k:pct%" where pct = v.hits*100/(v.hits+v.misses);
        //                           acc=="" ? line : "acc|line")
        //     api  : 90*100/100 = 90  -> "api:90%"
        //     db   : 40*100/100 = 40  -> "api:90%|db:40%"
        //     cache: 99*100/100 = 99  -> "api:90%|db:40%|cache:99%"
        // Byte-identical on interp/KVM (native per the sweep). Confirms Map.fold exposes both the key
        // and the record value to the closure, visits entries in insertion order, and that the
        // empty-accumulator branch omits the leading separator so the report has N-1 separators for N
        // entries (no leading "|"). This is the render-a-stats-table an AI writes for dashboards, log
        // summaries, or health reports. A backend that iterated the map in the wrong order would list
        // db before api, and one that mishandled the ac=="" guard would emit a leading separator.
        let src = r#"type Stat = { hits: Int, misses: Int }
fun probe() -> Str {
    let m: Map[Str, Stat] = Map().insert("api", Stat(hits: 90, misses: 10)).insert("db", Stat(hits: 40, misses: 60)).insert("cache", Stat(hits: 99, misses: 1))
    let report = m.fold("", fn(acc, k, v) {
        let total = v.hits + v.misses
        let pct = (v.hits * 100) / total
        let line = "{k}:{pct}%"
        if acc == "" { line } else { "{acc}|{line}" }
    })
    "{report}"
}
"#;
        assert_eq!(differential(src), "api:90%|db:40%|cache:99%");
    }

    #[test]
    fn diff_chunk_over_records_per_batch_average() {
        // A certification lock (it294): per-batch AVERAGE of a record field over non-overlapping
        // chunks -- the batch-mean idiom. it259 chunks plain Ints for a sum/size; this chunks RECORDS
        // (project the val field), and the load-bearing edge is that each batch's average divides by the
        // batch's OWN length, so the PARTIAL LAST CHUNK divides by its actual (smaller) size, not the
        // nominal chunk width.
        //   vals = [10, 20, 30, 44, 56, 100, 8]   (from Reading records)
        //   chunk(3) -> [[10,20,30], [44,56,100], [8]]
        //     sums / own-len: [60/3, 200/3, 8/1] == [20, 66, 8]
        //       (200/3 truncates to 66 by integer division; the singleton tail divides by 1 -> 8, NOT 8/3=2)
        //     nbatches = 3   (ceil(7/3))
        // Byte-identical on interp/KVM (native per the sweep). Confirms the per-batch mean uses
        // vals.len() (the real chunk size) as the divisor -- so the incomplete final batch averages over
        // 1 element, not 3 -- and that integer division truncates (200/3 -> 66). This is the batch/rolling
        // mean an AI writes for sensor sampling, paginated aggregates, or per-page stats. A backend that
        // divided every batch by the fixed chunk width would compute 8/3=2 for the tail, and one that
        // rounded instead of truncating would report 67 for the middle batch.
        let src = r#"type Reading = { sensor: Str, val: Int }
fun probe() -> Str {
    let rs = [Reading(sensor: "a", val: 10), Reading(sensor: "b", val: 20), Reading(sensor: "c", val: 30), Reading(sensor: "d", val: 44), Reading(sensor: "e", val: 56), Reading(sensor: "f", val: 100), Reading(sensor: "g", val: 8)]
    let avgs = rs.chunk(3).map(fn batch {
        let vals = batch.map(fn r { r.val })
        let sum = vals.fold(0, fn(a, v) { a + v })
        sum / vals.len()
    })
    "{avgs}|nbatches={avgs.len()}"
}
"#;
        assert_eq!(differential(src), "[20, 66, 8]|nbatches=3");
    }

    #[test]
    fn diff_window_over_records_high_low_range() {
        // A bug-hunt-39 lock (it293): the sliding high-low RANGE idiom over a series of records -- the
        // volatility-band / min-max-envelope shape. it257 windows plain Ints for a moving sum/max; this
        // windows RECORDS (extract the price field first), then computes BOTH a max and a min per window
        // via two folds with OPPOSITE sentinel seeds, and returns the range (hi - lo).
        //   prices  = [10, 14, 9, 20, 15]   (from Tick records)
        //   window(3) -> [[10,14,9], [14,9,20], [9,20,15]]
        //     max fold (seed -1000): [14, 20, 20]
        //     min fold (seed  1000): [ 9,  9,  9]
        //     range   = hi - lo    : [ 5, 11, 11]
        // Byte-identical on interp/KVM (native per the sweep). Confirms window() over records feeds each
        // overlapping sub-list through a field-projection then two independent sentinel-seeded folds, and
        // that the max-seed (-1000, low so any price wins) and min-seed (1000, high so any price wins)
        // point the right way. This is the moving high-low channel an AI writes for price volatility,
        // sensor min/max envelopes, or rolling range alerts. A backend that swapped the two seeds would
        // return a negative range, and one that lost the per-window field projection would fold over the
        // records themselves instead of the prices.
        let src = r#"type Tick = { t: Int, price: Int }
fun probe() -> Str {
    let ticks = [Tick(t: 1, price: 10), Tick(t: 2, price: 14), Tick(t: 3, price: 9), Tick(t: 4, price: 20), Tick(t: 5, price: 15)]
    let ranges = ticks.window(3).map(fn w {
        let prices = w.map(fn tk { tk.price })
        let hi = prices.fold(0 - 1000, fn(m, p) { if p > m { p } else { m } })
        let lo = prices.fold(1000, fn(m, p) { if p < m { p } else { m } })
        hi - lo
    })
    "{ranges}|{ranges.len()}"
}
"#;
        assert_eq!(differential(src), "[5, 11, 11]|3");
    }

    #[test]
    fn diff_fold_records_into_map_tally_by_key() {
        // A certification lock (it292): the manual "tally/aggregate into a Map via fold" idiom -- fold
        // over records with an EMPTY Map() accumulator, reading each record's field, using
        // get().unwrap_or(0) as the running total per key and insert() to update. it280 does sum-by-key
        // through the group_by BUILTIN; this pins the by-hand version an AI writes when it builds the
        // accumulator map directly (custom aggregation, or not knowing group_by exists).
        //   sales = [west+100, east+50, west+30, north+70, east+20]
        //   fold(Map(), (acc, s) -> acc.insert(s.region, acc.get(s.region).unwrap_or(0) + s.amt))
        //     totals == Map{"west": 130, "east": 70, "north": 70}
        //     keys()  == ["west", "east", "north"]   (FIRST-seen insertion order; west stays first
        //                                              even though its value is updated later)
        // Byte-identical on interp/KVM (native per the sweep). Confirms an empty Map seed threads
        // through fold, that inserting an EXISTING key updates its value in place WITHOUT moving it in
        // iteration order (west first-seen -> still first after its second update), that a fresh key
        // appends at the end, and that get().unwrap_or(0) supplies the zero for a key's first sighting.
        // This is the hand-rolled sum-by-key / word-count / bucket-tally an AI writes constantly. A
        // backend that re-ordered a key on update would list keys as east/north/west, and one that
        // dropped the get-or-zero would panic or miscount the first occurrence of each region.
        let src = r#"type Sale = { region: Str, amt: Int }
fun probe() -> Str {
    let sales = [Sale(region: "west", amt: 100), Sale(region: "east", amt: 50), Sale(region: "west", amt: 30), Sale(region: "north", amt: 70), Sale(region: "east", amt: 20)]
    let totals = sales.fold(Map(), fn(acc, s) {
        let prev = acc.get(s.region).unwrap_or(0)
        acc.insert(s.region, prev + s.amt)
    })
    let regions = totals.keys()
    let westTotal = totals.get("west").unwrap_or(0 - 1)
    "{regions}|west={westTotal}|{totals}"
}
"#;
        assert_eq!(
            differential(src),
            r#"["west", "east", "north"]|west=130|Map{"west": 130, "east": 70, "north": 70}"#
        );
    }

    #[test]
    fn diff_result_and_then_railway_over_record_payload() {
        // A bug-hunt-38 lock (it291): the Result railway (and_then) carrying a RECORD as the Ok
        // payload, updated at EACH step. it255 threads Int payloads through a validate pipeline; this
        // pins a stateful transaction -- an Account record flows through successive withdraw() calls,
        // each returning Result[Account, Str] and threading the UPDATED record (a with balance: ...)
        // via and_then. Three outcomes cover the railway's branches:
        //   withdraw(100, 30).and_then(withdraw 20) -> Ok(Account bal 50)   (both succeed, record threaded + updated twice)
        //   withdraw(100, 30).and_then(withdraw 200)-> Err("insufficient")  (first Ok, SECOND step fails mid-chain)
        //   withdraw(100, -5).and_then(withdraw 10) -> Err("bad amount")    (FIRST step Err -> and_then closure never runs)
        // Byte-identical on interp/KVM (native per the sweep). Confirms and_then feeds the Ok record
        // payload into the next fallible step and rebuilds it (100 -> 70 -> 50 across two withdrawals),
        // that an Err produced mid-chain (step 2) propagates its own message out, and that an Err at
        // step 1 short-circuits so the and_then closure is never invoked. This is the multi-step
        // transaction-with-early-exit an AI writes for money transfers, state machines, or staged
        // form submission -- where the thing flowing down the happy path is a structured record that
        // each stage transforms. A backend that lost the record update between and_then stages would
        // report bal 70 or 80 instead of 50, and one that ran the closure on an Err would misreport
        // the "bad amount" case.
        let src = r#"type Account = { id: Str, balance: Int }
fun withdraw(a: Account, amt: Int) -> Result[Account, Str] {
    if amt <= 0 { Err("bad amount") } else {
        if amt > a.balance { Err("insufficient") } else { Ok(a with balance: a.balance - amt) }
    }
}
fun outcome(r: Result[Account, Str]) -> Str {
    match r { Ok(a) => "ok:{a.balance}"
        Err(e) => "err:{e}" }
}
fun probe() -> Str {
    let acc = Account(id: "x1", balance: 100)
    let ok = withdraw(acc, 30).and_then(fn a { withdraw(a, 20) })
    let fail = withdraw(acc, 30).and_then(fn a { withdraw(a, 200) })
    let bad = withdraw(acc, 0 - 5).and_then(fn a { withdraw(a, 10) })
    "{outcome(ok)}|{outcome(fail)}|{outcome(bad)}"
}
"#;
        assert_eq!(differential(src), "ok:50|err:insufficient|err:bad amount");
    }

    #[test]
    fn diff_option_combinator_chain_over_records() {
        // A certification lock (it290): the Option-combinator chain over records -- find an entity in a
        // list (returns Option[Record]), then map a field / filter a predicate / unwrap_or a default,
        // WITHOUT a match expression. it286 reaches record fields through Option via `match`; this pins
        // the combinator style (map + filter + unwrap_or) and, crucially, the filter-rejects-to-None
        // short-circuit that skips the subsequent map. The four cases cover every branch:
        //   findByName("amy").map(age).unwrap_or(-1)                     -> 30      (found, mapped)
        //   findByName("bob").filter(age>=18).map(name).unwrap_or("minor")-> minor  (found, FILTERED OUT -> None -> map skipped -> default)
        //   findByName("cal").filter(active).map("name:age").unwrap_or(..)-> cal:45 (found, passes filter, mapped)
        //   findByName("zzz").map(name).unwrap_or("not-found")           -> not-found (never found -> None from the start)
        // Byte-identical on interp/KVM (native per the sweep). Confirms filter on a Some whose payload
        // fails the predicate collapses to None (so the chained map does not run and the default wins),
        // a Some flows its record payload through map's field projection, and a None from an empty
        // find().first() propagates untouched to unwrap_or. This is the null-safe "look up an entity and
        // safely extract a field with a fallback" navigation an AI writes constantly; a backend that let
        // a filtered-out Some leak into map, or that lost the record payload across the chain, would
        // diverge on the "minor" case while the straight found/not-found cases looked fine.
        let src = r#"type User = { name: Str, age: Int, active: Bool }
fun findByName(users: List[User], target: Str) -> Option[User] {
    let matches = users.filter(fn u { u.name == target })
    matches.first()
}
fun probe() -> Str {
    let users = [User(name: "amy", age: 30, active: true), User(name: "bob", age: 17, active: false), User(name: "cal", age: 45, active: true)]
    let amyAge = findByName(users, "amy").map(fn u { u.age }).unwrap_or(0 - 1)
    let bobAdult = findByName(users, "bob").filter(fn u { u.age >= 18 }).map(fn u { u.name }).unwrap_or("minor")
    let calActive = findByName(users, "cal").filter(fn u { u.active }).map(fn u { "{u.name}:{u.age}" }).unwrap_or("inactive")
    let ghost = findByName(users, "zzz").map(fn u { u.name }).unwrap_or("not-found")
    "{amyAge}|{bobAdult}|{calActive}|{ghost}"
}
"#;
        assert_eq!(differential(src), "30|minor|cal:45|not-found");
    }

    #[test]
    fn diff_zip_with_over_two_heterogeneous_record_lists() {
        // A bug-hunt-37 lock (it289): zip_with combining two lists of DIFFERENT record types by
        // position -- the "join two parallel streams positionally" idiom. it1983 locks zip_with's
        // truncate-to-shorter on Int lists; this pins the closure destructuring fields off BOTH element
        // records at once (Item AND Price) and confirms truncation still drops the tail of the longer
        // list when the elements are records.
        //   items  = [apple:3, pear:2, fig:5]   (3 Item records)
        //   prices = [A:10, B:20]               (2 Price records)
        //   zip_with((it, p) -> "{it.name}x{it.qty}@{p.cost}={it.qty * p.cost}")
        //     -> ["applex3@10=30", "pearx2@20=40"]   (fig has no price partner, dropped)
        //     -> length 2 (min of 3 and 2)
        // Byte-identical on interp/KVM (native per the sweep). Confirms zip_with reads fields from two
        // distinct record types in the same closure and truncates to the shorter list even when both
        // sides carry structured records -- the positional inventory/price-join an AI writes to combine
        // two aligned tables. A backend that ran to the longer length would index past the price list on
        // `fig`, and one that mishandled the two element types would cross the fields up.
        let src = r#"type Item = { name: Str, qty: Int }
type Price = { sku: Str, cost: Int }
fun probe() -> Str {
    let items = [Item(name: "apple", qty: 3), Item(name: "pear", qty: 2), Item(name: "fig", qty: 5)]
    let prices = [Price(sku: "A", cost: 10), Price(sku: "B", cost: 20)]
    let lines = items.zip_with(prices, fn(it, p) { "{it.name}x{it.qty}@{p.cost}={it.qty * p.cost}" })
    "{lines}|{lines.len()}"
}
"#;
        assert_eq!(
            differential(src),
            r#"["applex3@10=30", "pearx2@20=40"]|2"#
        );
    }

    #[test]
    fn diff_sort_by_records_descending_via_negated_key() {
        // A certification lock (it288): descending sort of records by a numeric field. sort_by is a
        // key-extractor that sorts ASCENDING and is STABLE (locked generally); this pins the canonical
        // way to get DESCENDING order -- negate the key with `0 - field` -- and confirms tie-stability
        // survives the negation. This is the "leaderboard / rank by score, highest first" idiom, the
        // single most common non-default sort direction an AI reaches for, and KUPL's sort_by has no
        // reverse flag, so the negated-key trick IS the idiom.
        //   players scored [amy:50, bob:90, cal:50, dan:70]
        //   sort_by(0 - p.score) -> keys [-50, -90, -50, -70], ascending -> bob:90, dan:70, amy:50, cal:50
        //   amy (50) stays before cal (50): negation is monotonic and the sort is stable, so the two
        //   ties keep their original relative order rather than swapping.
        // Byte-identical on interp/KVM (native per the sweep). Confirms that reversing sort direction by
        // key negation preserves stability on equal keys -- a backend whose sort was unstable, or that
        // mishandled the negative key, would flip amy/cal while the strictly-ordered scores looked fine.
        let src = r#"type Player = { name: Str, score: Int }
fun probe() -> Str {
    let ps = [Player(name: "amy", score: 50), Player(name: "bob", score: 90), Player(name: "cal", score: 50), Player(name: "dan", score: 70)]
    let desc = ps.sort_by(fn p { 0 - p.score })
    let names = desc.map(fn p { "{p.name}:{p.score}" })
    "{names.join(",")}"
}
"#;
        assert_eq!(differential(src), "bob:90,dan:70,amy:50,cal:50");
    }

    #[test]
    fn diff_map_of_records_lookup_and_aggregate() {
        // A certification lock (it286): the "entity store" idiom -- records indexed by a string ID
        // in a Map[Str, User], then looked up and aggregated. it276 transforms record VALUES in place
        // (map_values); this pins the READ side: get() returns Option[the record], a match reaches a
        // field on the Some branch (u.city), a missing key takes the None branch, and values() feeds
        // fold/filter/map that project and aggregate record FIELDS.
        //   byId = {"u1": User(amy,30,NYC), "u2": User(bob,25,LA), "u3": User(cal,35,NYC)}
        //   get("u1") -> Some(User) -> .city == "NYC"      (present key, field reached through Option)
        //   get("u9") -> None -> "none"                    (absent key takes the None arm)
        //   values().fold(0, +age) == 90                   (30 + 25 + 35, aggregate over a record field)
        //   values().filter(city=="NYC").map(name) == ["amy", "cal"]   (project a field, insertion order)
        // Byte-identical on interp/KVM (native per the sweep). Confirms Map values carry full record
        // structure through get()/values(), field access composes on the Option's Some payload, and the
        // dictionary-of-objects lookup-then-aggregate pattern agrees across engines.
        let src = r#"type User = { name: Str, age: Int, city: Str }
fun probe() -> Str {
    let byId: Map[Str, User] = Map().insert("u1", User(name: "amy", age: 30, city: "NYC")).insert("u2", User(name: "bob", age: 25, city: "LA")).insert("u3", User(name: "cal", age: 35, city: "NYC"))
    let amyCity = match byId.get("u1") { Some(u) => u.city
        None => "?" }
    let missing = match byId.get("u9") { Some(u) => u.name
        None => "none" }
    let totalAge = byId.values().fold(0, fn(a, u) { a + u.age })
    let nycUsers = byId.values().filter(fn u { u.city == "NYC" }).map(fn u { u.name })
    "{amyCity}|{missing}|{totalAge}|{nycUsers}"
}
"#;
        assert_eq!(differential(src), r#"NYC|none|90|["amy", "cal"]"#);
    }

    #[test]
    fn diff_scan_over_records_with_record_accumulator() {
        // A bug-hunt-36 lock (it285): scan where BOTH the elements AND the accumulator are records --
        // the "running balance over a transaction ledger" idiom. it274 scans a list of Ints into a
        // record accumulator; this pins the closure destructuring the ELEMENT record (t.delta) while
        // threading the STATE record (Bal), including negative deltas that decrease the running total.
        //   txns = [deposit +100, withdraw -30, deposit +50, fee -5]  (each a Txn record)
        //   scan(Bal(total:0, count:0), (b,t) -> Bal(b.total + t.delta, b.count + 1))
        //     running balances (scan excludes the seed) == [100, 70, 120, 115]
        //     final == Bal(total: 115, count: 4)
        // Byte-identical on interp/KVM (native per the sweep). Confirms scan reads a field off each
        // element record and constructs a fresh accumulator record per step, so a running-total that
        // both rises (deposits) and falls (withdrawals/fees) tracks correctly, and .last() recovers the
        // final state.
        let src = r#"type Txn = { desc: Str, delta: Int }
type Bal = { total: Int, count: Int }
fun probe() -> Str {
    let txns = [Txn(desc: "deposit", delta: 100), Txn(desc: "withdraw", delta: 0 - 30), Txn(desc: "deposit", delta: 50), Txn(desc: "fee", delta: 0 - 5)]
    let running = txns.scan(Bal(total: 0, count: 0), fn(b, t) { Bal(total: b.total + t.delta, count: b.count + 1) })
    let balances = running.map(fn b { b.total })
    let final = running.last().unwrap_or(Bal(total: 0, count: 0))
    "{balances}|final={final.total} n={final.count}"
}
"#;
        assert_eq!(differential(src), "[100, 70, 120, 115]|final=115 n=4");
    }

    #[test]
    fn diff_nested_if_cascade_grade_classification() {
        // A certification lock (it284): the cascading-threshold classification idiom -- a deep
        // nested-if (if/else-if chain) that maps a numeric score into one of five named buckets by
        // DESCENDING thresholds, applied over records, then group_by + count. it256 locks nested-if
        // inside a match arm; this pins the standalone 4-deep if-else cascade as a range-bucketizer
        // (grading, tiering, severity classification) composed with a histogram.
        //   grade: s>=90 -> A ; else s>=80 -> B ; else s>=70 -> C ; else s>=60 -> D ; else F
        //   scores [95, 82, 71, 55, 88, 90] -> [A, B, C, F, B, A]   (90 is boundary-inclusive -> A; 55 -> F)
        //   group_by(grade) + map_values(len) -> Map{"A": 2, "B": 2, "C": 1, "F": 1}   (no "D" bucket, first-seen order)
        // Byte-identical on interp/KVM (native per the sweep). Confirms the cascade picks the FIRST
        // threshold met (outer-if wins, so 95 is A not B), the >=90 boundary is inclusive, and the
        // empty "D" tier simply doesn't appear in the histogram.
        let src = r#"type Student = { name: Str, score: Int }
fun grade(s: Int) -> Str {
    if s >= 90 { "A" } else {
        if s >= 80 { "B" } else {
            if s >= 70 { "C" } else {
                if s >= 60 { "D" } else { "F" }
            }
        }
    }
}
fun probe() -> Str {
    let students = [Student(name: "amy", score: 95), Student(name: "bob", score: 82), Student(name: "cal", score: 71), Student(name: "dan", score: 55), Student(name: "eve", score: 88), Student(name: "fox", score: 90)]
    let graded = students.map(fn s { grade(s.score) })
    let byGrade = graded.group_by(fn g { g })
    let counts = byGrade.map_values(fn gs { gs.len() })
    "{graded.join(",")}|{counts}"
}
"#;
        assert_eq!(
            differential(src),
            r#"A,B,C,F,B,A|Map{"A": 2, "B": 2, "C": 1, "F": 1}"#
        );
    }

    #[test]
    fn diff_take_while_drop_while_complementary_on_records() {
        // A bug-hunt-35 lock (it282): take_while and drop_while are COMPLEMENTARY -- they split a list
        // at exactly the same boundary (the first element failing the predicate), so taken ++ dropped
        // reconstructs the original. Prior take_while/drop_while locks (it1993/2824/4454) use SCALAR
        // predicates; this pins the pair on RECORDS with a FIELD predicate, the "consume events until a
        // field condition changes" idiom (log lines until the first error, samples until a threshold).
        //   evs = [ok/1, ok/2, err/3, ok/4]
        //   take_while(kind=="ok") stops at the first err -> [1, 2]   (does NOT resume at ok/4)
        //   drop_while(kind=="ok") drops the leading oks   -> [3, 4]   (keeps everything from first err on)
        //   [taken, dropped].flatten() == evs   (the two halves partition the list at the same cut)
        //   taken.len() + dropped.len() == evs.len()
        // Byte-identical on interp/KVM (native per the sweep). Confirms both scan left-to-right, both
        // stop/start at the SAME first-failure boundary (not resuming after a later pass), and that the
        // field predicate reads e.kind correctly on each record.
        let src = r#"type Ev = { ts: Int, kind: Str }
fun probe() -> Str {
    let evs = [Ev(ts: 1, kind: "ok"), Ev(ts: 2, kind: "ok"), Ev(ts: 3, kind: "err"), Ev(ts: 4, kind: "ok")]
    let taken = evs.take_while(fn e { e.kind == "ok" })
    let dropped = evs.drop_while(fn e { e.kind == "ok" })
    let rebuilt = [taken, dropped].flatten().map(fn e { e.ts })
    let origTs = evs.map(fn e { e.ts })
    "{taken.map(fn e { e.ts })}|{dropped.map(fn e { e.ts })}|{rebuilt == origTs}|{taken.len() + dropped.len() == evs.len()}"
}
"#;
        assert_eq!(differential(src), "[1, 2]|[3, 4]|true|true");
    }

    #[test]
    fn diff_full_pivot_filter_sort_group_max_per_group() {
        // A certification lock (it281): the complete analytics-query pipeline over records --
        // filter -> sort_by -> group_by -> fold(max record per group) -> map_values(format). it280
        // locked group_by+SUM in isolation; this pins the FULL five-stage chain an AI writes for a
        // report, and specifically two interactions the isolated locks can't: (a) group_by's first-seen
        // key order reflects the ORDER AFTER sorting (not the original list order), and (b) the
        // per-group reduction picks the MAX record by a field (returning a whole record, not a scalar).
        //   sales filtered to amt>=20 -> [west/amy/30, east/bob/50, west/cal/20, west/eve/40]
        //   sort_by(amt) -> [west/cal/20, west/amy/30, west/eve/40, east/bob/50]
        //   group_by(region) keys in post-sort first-seen order == ["west", "east"]   (west's cal/20 seen first)
        //   fold each group to its max-amt record, format rep=amt -> {west: "eve=40", east: "bob=50"}
        // Byte-identical on interp/KVM (native per the sweep). Confirms the five stages compose: the
        // filter drops dan/10, the sort reorders so west is first-seen, group_by buckets in that order,
        // and the per-group fold returns the winning RECORD (eve for west, bob for east).
        let src = r#"type Sale = { region: Str, rep: Str, amt: Int }
fun probe() -> Str {
    let sales = [
        Sale(region: "west", rep: "amy", amt: 30),
        Sale(region: "east", rep: "bob", amt: 50),
        Sale(region: "west", rep: "cal", amt: 20),
        Sale(region: "east", rep: "dan", amt: 10),
        Sale(region: "west", rep: "eve", amt: 40)
    ]
    let big = sales.filter(fn s { s.amt >= 20 })
    let sorted = big.sort_by(fn s { s.amt })
    let byRegion = sorted.group_by(fn s { s.region })
    let topPerRegion = byRegion.map_values(fn ss {
        ss.fold(ss.first().unwrap_or(Sale(region: "", rep: "", amt: 0)), fn(best, s) { if s.amt > best.amt { s } else { best } })
    })
    let summary = topPerRegion.map_values(fn s { "{s.rep}={s.amt}" })
    "{byRegion.keys()}|{summary}"
}
"#;
        assert_eq!(
            differential(src),
            r#"["west", "east"]|Map{"west": "eve=40", "east": "bob=50"}"#
        );
    }

    #[test]
    fn diff_group_by_records_then_sum_field_per_group() {
        // A bug-hunt-34 lock (it280): the SQL "GROUP BY key, SUM(field)" aggregation over RECORDS.
        // it262 groups STRINGS by first-char then COUNTS (map_values(len)); this pins grouping RECORDS
        // by one field and reducing each group by SUMMING a DIFFERENT field -- the canonical
        // group-transactions-by-account, total-the-amounts idiom.
        //   txns = [Txn(a,10), Txn(b,20), Txn(a,5), Txn(c,8), Txn(b,3)]
        //   group_by(.user) -> {a:[Txn(a,10),Txn(a,5)], b:[Txn(b,20),Txn(b,3)], c:[Txn(c,8)]}  (first-seen order)
        //   map_values(fold sum .amt) -> Map{"a": 15, "b": 23, "c": 8}
        //   keys() == ["a", "b", "c"]  (bucket order = first appearance of each user)
        // Byte-identical on interp/KVM (native per the sweep). Confirms group_by keys records by a
        // field-derived value in first-seen order, and that folding each group over a SECOND field
        // (not a count) produces the correct per-group total.
        let src = r#"type Txn = { user: Str, amt: Int }
fun probe() -> Str {
    let txns = [Txn(user: "a", amt: 10), Txn(user: "b", amt: 20), Txn(user: "a", amt: 5), Txn(user: "c", amt: 8), Txn(user: "b", amt: 3)]
    let byUser = txns.group_by(fn t { t.user })
    let totals = byUser.map_values(fn ts { ts.fold(0, fn(a, t) { a + t.amt }) })
    "{byUser.keys()}|{totals}"
}
"#;
        assert_eq!(
            differential(src),
            r#"["a", "b", "c"]|Map{"a": 15, "b": 23, "c": 8}"#
        );
    }

    #[test]
    fn diff_string_case_conversion_pipeline() {
        // A certification lock (it279): identifier-case conversion between naming conventions, the
        // split -> map(case-transform) -> join pipeline. it253 locked split-parse-join for NUMBERS;
        // this pins the STRING case-transform composition an AI writes constantly for codegen, config
        // mapping, and API-field translation -- snake_case to Title Case to CONSTANT_CASE and back.
        //   snake = "hello_world_foo"
        //   titled    = split("_").map(capitalize).join(" ")   == "Hello World Foo"
        //   constant  = titled.split(" ").map(to_upper).join("_") == "HELLO_WORLD_FOO"
        //   camelish  = snake.split("_").map(to_upper).join("")   == "HELLOWORLDFOO"
        //   roundtrip = titled.to_lower().replace(" ", "_")       == "hello_world_foo"  (back to snake)
        // Byte-identical on interp/KVM (native per the sweep). Confirms capitalize (first-char upper,
        // rest lower), to_upper/to_lower on words, join with varied separators ("_", " ", ""), and that
        // the composition round-trips cleanly from snake through Title back to snake.
        let src = r#"fun probe() -> Str {
    let snake = "hello_world_foo"
    let titled = snake.split("_").map(fn w { w.capitalize() }).join(" ")
    let constant = titled.split(" ").map(fn w { w.to_upper() }).join("_")
    let camelish = snake.split("_").map(fn w { w.to_upper() }).join("")
    let roundtrip = titled.to_lower().replace(" ", "_")
    "{titled}|{constant}|{camelish}|{roundtrip}"
}
"#;
        assert_eq!(
            differential(src),
            "Hello World Foo|HELLO_WORLD_FOO|HELLOWORLDFOO|hello_world_foo"
        );
    }

    #[test]
    fn diff_window_map_fold_into_record_per_window() {
        // A bug-hunt-33 lock (it278): sliding-window aggregation where each window is folded into a
        // RECORD summary in a SINGLE pass. it257 locked window->scalar moving-stats (separate movsum
        // and movmax passes, each an Int); this pins window().map(fold-into-record), computing min, max,
        // AND sum for each window together in one fold -- the "moving multi-field bar" idiom (a
        // candlestick per window, a moving low/high/total). Composes window (it165/257) with the
        // record-accumulator fold (it275).
        //   xs = [3,1,4,1,5,9], window(3) -> [3,1,4] [1,4,1] [4,1,5] [1,5,9]
        //   each folded to Win(lo, hi, sum):
        //     [3,1,4] -> [1,4,8]   [1,4,1] -> [1,4,6]   [4,1,5] -> [1,5,10]   [1,5,9] -> [1,9,15]
        // Byte-identical on interp/KVM (native per the sweep). Confirms each window's fold builds an
        // independent record with all three fields advancing in one pass, and the per-window records
        // render in window order.
        let src = r#"type Win = { lo: Int, hi: Int, sum: Int }
fun probe() -> Str {
    let xs = [3, 1, 4, 1, 5, 9]
    let wins = xs.window(3).map(fn w {
        w.fold(Win(lo: 999, hi: 0 - 999, sum: 0), fn(a, x) {
            Win(lo: if x < a.lo { x } else { a.lo }, hi: if x > a.hi { x } else { a.hi }, sum: a.sum + x)
        })
    })
    let strs = wins.map(fn w { "[{w.lo},{w.hi},{w.sum}]" })
    "{strs.join(" ")}"
}
"#;
        assert_eq!(differential(src), "[1,4,8] [1,4,6] [1,5,10] [1,9,15]");
    }

    #[test]
    fn diff_map_fold_into_record_over_keys_and_values() {
        // A certification lock (it277): Map.fold's 3-arg (acc, k, v) form threading a RECORD
        // accumulator that reads BOTH the key and the value at each entry. Prior Map.fold locks build a
        // Map (it2370-2374) or a String (it4923); it275's fold-to-record uses List's 2-arg fold. This
        // pins the distinct "reduce a map's entries into a summary record" idiom, where each step
        // consumes k AND v -- summing values, accumulating key lengths, counting entries -- into a
        // structured accumulator.
        //   m = {"aa":5, "bbb":10, "c":3}, seed Agg(total:0, keyLens:0, entries:0)
        //   total   = sum of values           == 5+10+3 == 18
        //   keyLens = sum of key char-lengths == 2+3+1  == 6
        //   entries = count                   == 3
        //   avg = total/entries == 6 (integer division)
        // Byte-identical on interp/KVM (native per the sweep). Confirms Map.fold visits every entry
        // exactly once, exposes both k and v to the closure, and threads a fresh record forward with
        // all three fields advancing per entry.
        let src = r#"type Agg = { total: Int, keyLens: Int, entries: Int }
fun probe() -> Str {
    let m = Map().insert("aa", 5).insert("bbb", 10).insert("c", 3)
    let r = m.fold(Agg(total: 0, keyLens: 0, entries: 0), fn(a, k, v) {
        Agg(total: a.total + v, keyLens: a.keyLens + k.chars().len(), entries: a.entries + 1)
    })
    let avgVal = r.total / r.entries
    "total={r.total} keyLens={r.keyLens} entries={r.entries} avg={avgVal}"
}
"#;
        assert_eq!(differential(src), "total=18 keyLens=6 entries=3 avg=6");
    }

    #[test]
    fn diff_map_values_record_transform_recompute_field() {
        // A bug-hunt-32 lock (it276): Map.map_values transforming RECORD values into new records.
        // Prior map_values locks use scalar (it4895: v*10) or list-len (it2468) transforms; this pins
        // the "map of records -> recompute a derived field for every entry" idiom, where the closure
        // reads a record's fields and constructs a FRESH record, and the map's keys and insertion order
        // are preserved 1:1.
        //   m = {"a": Item(qty:2, price:10), "b": Item(qty:3, price:5)}
        //   map_values(it -> Item(qty: it.qty, price: it.qty * it.price))
        //     == {"a": Item(2, 20), "b": Item(3, 15)}   // price recomputed = qty*price, qty kept
        //   totals.get("a") == Some(Item(2, 20))        // value-by-key round-trips the new record
        //   totals.keys()   == ["a", "b"]               // keys/order untouched
        // Byte-identical on interp/KVM (native per the sweep). Confirms map_values applies the closure to
        // each record value producing a new record, the record Display renders positionally, and the
        // 1:1 key/order invariant holds through the transform.
        let src = r#"type Item = { qty: Int, price: Int }
fun probe() -> Str {
    let m = Map().insert("a", Item(qty: 2, price: 10)).insert("b", Item(qty: 3, price: 5))
    let totals = m.map_values(fn it { Item(qty: it.qty, price: it.qty * it.price) })
    "{totals}|{totals.get("a")}|{totals.keys()}"
}
"#;
        assert_eq!(
            differential(src),
            r#"Map{"a": Item(2, 20), "b": Item(3, 15)}|Some(Item(2, 20))|["a", "b"]"#
        );
    }

    #[test]
    fn diff_fold_with_record_stats_single_pass() {
        // A certification lock (it275): fold reducing to a RECORD accumulator that computes four
        // summary statistics (min/max/sum/count) in a SINGLE pass. This complements it274 (scan with a
        // record acc) but pins fold's distinct contract: scan emits the state after every element;
        // fold emits ONLY the final accumulator. It is the canonical "aggregate a list into a stats
        // struct" idiom -- one traversal, four fields advancing independently, then derived values.
        //   xs = [7, 2, 9, 4, 2, 8], seed Stats(lo:999, hi:-999, sum:0, cnt:0)
        //   lo == 2  (running min)   hi == 9  (running max)   sum == 32   cnt == 6
        //   mean = sum/cnt == 5 (integer division)   range = hi-lo == 7
        // Byte-identical on interp/KVM (native per the sweep). Confirms fold threads a multi-field
        // record through the whole list with each field's own update rule (conditional for min/max,
        // additive for sum/cnt), and that only the final record survives to drive the derived stats.
        let src = r#"type Stats = { lo: Int, hi: Int, sum: Int, cnt: Int }
fun probe() -> Str {
    let xs = [7, 2, 9, 4, 2, 8]
    let s = xs.fold(Stats(lo: 999, hi: 0 - 999, sum: 0, cnt: 0), fn(a, x) {
        Stats(
            lo: if x < a.lo { x } else { a.lo },
            hi: if x > a.hi { x } else { a.hi },
            sum: a.sum + x,
            cnt: a.cnt + 1
        )
    })
    let mean = s.sum / s.cnt
    let range = s.hi - s.lo
    "lo={s.lo} hi={s.hi} sum={s.sum} cnt={s.cnt} mean={mean} range={range}"
}
"#;
        assert_eq!(differential(src), "lo=2 hi=9 sum=32 cnt=6 mean=5 range=7");
    }

    #[test]
    fn diff_scan_with_record_shaped_accumulator() {
        // A bug-hunt-31 lock (it274): List.scan threading a RECORD-shaped running state. Prior scan
        // locks (it2007-2016) all use a SCALAR accumulator -- Int running-sum, running-max, String
        // concat. This pins scan carrying a structured multi-field accumulator (running sum AND count
        // together), the "running aggregate" idiom an AI writes for a moving average or a min/max pair.
        //   scan(Acc(sum:0, cnt:0), fn(a,x) { Acc(sum: a.sum+x, cnt: a.cnt+1) }) over [10,20,30,40]
        //   states.map(.sum)                 == [10, 30, 60, 100]   // scan EXCLUDES the seed (per it2007)
        //   states.drop(1).map(.sum/.cnt)    == [15, 20, 25]        // running average from field 2 onward
        //   states.len()                     == 4
        // Byte-identical on interp/KVM (native per the sweep). Confirms scan constructs a fresh record
        // per step, both fields advance in lockstep, and the seed is not emitted -- so downstream field
        // access (a.sum / a.cnt) sees the correct paired state at every position.
        let src = r#"type Acc = { sum: Int, cnt: Int }
fun probe() -> Str {
    let xs = [10, 20, 30, 40]
    let states = xs.scan(Acc(sum: 0, cnt: 0), fn(a, x) { Acc(sum: a.sum + x, cnt: a.cnt + 1) })
    let sums = states.map(fn a { a.sum })
    let avgs = states.drop(1).map(fn a { a.sum / a.cnt })
    "{sums}|{avgs}|{states.len()}"
}
"#;
        assert_eq!(differential(src), "[10, 30, 60, 100]|[15, 20, 25]|4");
    }

    #[test]
    fn diff_option_ok_or_result_bridge_in_function() {
        // A certification lock (it273): the Option->Result BRIDGE. A lookup returns Option (Map.get),
        // ok_or converts it to a Result with a DYNAMIC error message carrying the missing key, and the
        // resulting Result then flows through map/and_then/unwrap_or as a railway. Prior locks cover
        // ok_or in isolation (it4175/4552) and Result combinators without the bridge (it269); this pins
        // the whole "optional lookup -> fallible pipeline" pattern in a typed function, which is how an
        // AI turns a missing-key case into a contextualized error.
        //   lookup(m,k) = m.get(k).ok_or("missing: {k}")   // Option -> Result[Int, Str]
        //   lookup(m,"a").map(*10)                    == Ok(40)             // Some -> Ok, map transforms
        //   lookup(m,"z").map(*10)                    == Err("missing: z")  // None -> Err (dynamic msg), map skips
        //   lookup(m,"b").and_then(even?)             == Err("odd: 7")      // Ok(7) -> fresh Err mid-chain
        //   lookup(m,"a").and_then(even?).unwrap_or(-1) == 4                // Ok(4) survives, unwrap
        //   lookup(m,"z").unwrap_or(-99)              == -99                // Err recovers to default
        // Byte-identical on interp/KVM (native per the sweep). The bridge is ok_or: it is the single
        // point where "value might be absent" becomes "operation might fail with a reason".
        let src = r#"fun lookup(m: Map[Str, Int], k: Str) -> Result[Int, Str] {
    m.get(k).ok_or("missing: {k}")
}
fun probe() -> Str {
    let m = Map().insert("a", 4).insert("b", 7)
    let r1 = lookup(m, "a").map(fn x { x * 10 })
    let r2 = lookup(m, "z").map(fn x { x * 10 })
    let r3 = lookup(m, "b").and_then(fn x { if x % 2 == 0 { Ok(x) } else { Err("odd: {x}") } })
    let r4 = lookup(m, "a").and_then(fn x { if x % 2 == 0 { Ok(x) } else { Err("odd: {x}") } }).unwrap_or(0 - 1)
    let r5 = lookup(m, "z").unwrap_or(0 - 99)
    "{r1}|{r2}|{r3}|{r4}|{r5}"
}
"#;
        assert_eq!(
            differential(src),
            r#"Ok(40)|Err("missing: z")|Err("odd: 7")|4|-99"#
        );
    }

    #[test]
    fn diff_list_position_first_match_and_none() {
        // A bug-hunt-30 lock (it272): List.position's first-match guarantee and its None cases.
        // it2992 tests position with a single predicate but not the FIRST-of-duplicates guarantee --
        // when several elements satisfy the predicate, position returns the index of the FIRST one,
        // not the last, and returns None when nothing matches or the list is empty.
        //   [10,20,30,20,40].position(== 20) == Some(1)   // first 20 (index 1), NOT the one at index 3
        //   [10,20,30,20,40].position(> 25)  == Some(2)   // first element > 25 is 30 at index 2
        //   [10,20,30,20,40].position(== 99) == None      // no match
        //   [].position(> 0)                 == None      // empty
        //   [1,5,3,5,5].position(== 5)       == Some(1)   // first 5 (index 1), NOT index 3 or 4
        // Byte-identical on interp/KVM (native per the sweep). Pins left-to-right scan returning the
        // earliest index, and None (not a sentinel like -1) on absence.
        let src = r#"fun probe() -> Str {
    let xs = [10, 20, 30, 20, 40]
    let exact = xs.position(fn x { x == 20 })
    let pred = xs.position(fn x { x > 25 })
    let missing = xs.position(fn x { x == 99 })
    let mt: List[Int] = []
    let empty = mt.position(fn x { x > 0 })
    let firstBoth = [1, 5, 3, 5, 5].position(fn x { x == 5 })
    "{exact}|{pred}|{missing}|{empty}|{firstBoth}"
}
"#;
        assert_eq!(differential(src), "Some(1)|Some(2)|None|None|Some(1)");
    }

    #[test]
    fn diff_map_merge_conflict_resolution_noncommutative() {
        // A certification lock (it271): Map.merge's conflict-resolution and its NON-commutativity.
        // Prior locks (it4226/4742) exercise merge in a single direction; this pins that
        // a.merge(b) != b.merge(a) in BOTH the winning values AND the key order, which is the property
        // an AI must get right when layering config/overrides. The ARGUMENT wins on key collision; the
        // receiver's existing keys keep their positions and the argument's NEW keys are appended.
        //   base = {a:1, b:2, c:3}   over = {b:20, c:30, d:40}
        //   base.merge(over) == {a:1, b:20, c:30, d:40}   // over wins b,c; a kept; d appended
        //   over.merge(base) == {b:2, c:3, d:40, a:1}      // base wins b,c; d kept; a appended (different order!)
        //   base.merge(over).keys()   == [a, b, c, d]      base.merge(over).values() == [1, 20, 30, 40]
        // Byte-identical on interp/KVM (native per the sweep). The two directions produce different maps
        // because merge is left-biased in ordering and right-biased in value — precedence depends on
        // which map is the override.
        let src = r#"fun probe() -> Str {
    let base = Map().insert("a", 1).insert("b", 2).insert("c", 3)
    let over = Map().insert("b", 20).insert("c", 30).insert("d", 40)
    let merged = base.merge(over)
    let mergedRev = over.merge(base)
    "{merged}|{mergedRev}|{merged.keys()}|{merged.values()}"
}
"#;
        assert_eq!(
            differential(src),
            r#"Map{"a": 1, "b": 20, "c": 30, "d": 40}|Map{"b": 2, "c": 3, "d": 40, "a": 1}|["a", "b", "c", "d"]|[1, 20, 30, 40]"#
        );
    }

    #[test]
    fn diff_list_all_any_vacuous_on_empty() {
        // A bug-hunt-29 lock (it270): the vacuous-quantifier edge of all()/any(). Prior locks
        // (it2941/2202/5800) exercise all/any on NON-empty lists; this pins the empty-list convention
        // that trips many implementations: all() over an empty list is TRUE (a universal quantifier
        // over no elements is vacuously satisfied — there is no counterexample), and any() over an
        // empty list is FALSE (an existential over no elements has no witness). On [2,4,6,8]:
        // all(even)=true, any(odd)=false; on []: all(>0)=true (vacuous), any(>0)=false (vacuous);
        // and [2,4,5,6].all(even)=false because 5 is a real counterexample. Byte-identical on
        // interp/KVM (native per the sweep).
        let src = r#"fun probe() -> Str {
    let xs = [2, 4, 6, 8]
    let mt: List[Int] = []
    let allEven = xs.all(fn x { x % 2 == 0 })
    let anyOdd = xs.any(fn x { x % 2 == 1 })
    let allEmpty = mt.all(fn x { x > 0 })
    let anyEmpty = mt.any(fn x { x > 0 })
    let mixed = [2, 4, 5, 6].all(fn x { x % 2 == 0 })
    "{allEven}|{anyOdd}|{allEmpty}|{anyEmpty}|{mixed}"
}
"#;
        assert_eq!(differential(src), "true|false|true|false|false");
    }

    #[test]
    fn diff_result_and_then_map_map_err_interleaved() {
        // A certification lock (it269): the full Result-combinator interleaving in one chain, where
        // each of and_then/map/map_err exhibits its DUAL behavior (transform one variant, pass the
        // other through). it255 locked a multi-stage all-and_then railway; it4098 locked map/map_err/
        // unwrap_or/ok on single Results; neither pins the three interleaved so that map's
        // Err-passthrough, map_err's Ok-passthrough, and an and_then producing a NEW error mid-chain
        // all appear together. half(n) = Ok(n/2) if even else Err("odd: {n}").
        //   a: Ok(40).and_then(half)=Ok(20).map(+1)=Ok(21).and_then(half) -> Err("odd: 21")  (new err mid-chain)
        //   b: Ok(7).and_then(half)=Err.map(+1) -> Err("odd: 7")                             (map skips Err)
        //   c: Ok(7).and_then(half)=Err.map_err(wrap) -> Err("wrapped[odd: 7]")              (map_err transforms Err)
        //   d: Ok(40).and_then(half).and_then(half)=Ok(10).map_err(..)=Ok(10).unwrap_or(-1) -> 10  (map_err skips Ok)
        // Byte-identical on interp/KVM (native per the sweep).
        let src = r#"fun half(n: Int) -> Result[Int, Str] { if n % 2 == 0 { Ok(n / 2) } else { Err("odd: {n}") } }
fun probe() -> Str {
    let a = Ok(40).and_then(half).map(fn x { x + 1 }).and_then(half)
    let b = Ok(7).and_then(half).map(fn x { x + 1 })
    let c = Ok(7).and_then(half).map_err(fn e { "wrapped[{e}]" })
    let d = Ok(40).and_then(half).and_then(half).map_err(fn e { "E:{e}" }).unwrap_or(0 - 1)
    "{a}|{b}|{c}|{d}"
}
"#;
        assert_eq!(
            differential(src),
            r#"Err("odd: 21")|Err("odd: 7")|Err("wrapped[odd: 7]")|10"#
        );
    }

    #[test]
    fn diff_set_symmetric_difference_chain() {
        // A bug-hunt-28 lock (it268): chaining symmetric_difference, which is associative and whose
        // n-way chain yields the elements appearing in an ODD number of the sets (set XOR). Prior
        // set-algebra locks (it123/161/183/205/216/235/242/251) cover union/intersect/difference and
        // composed chains, but not symmetric_difference chained across three sets. a = {1,2,3,4},
        // b = {3,4,5,6}, c = {5,6,7,8}. a △ b drops the shared {3,4}, keeping {1,2,5,6}; then
        // (a △ b) △ c drops the shared {5,6} and adds {7,8}, yielding {1,2,7,8} — exactly the
        // elements in an odd number of {a,b,c} (1,2 in a only; 7,8 in c only; 3,4 in two; 5,6 in
        // two). Byte-identical on interp/KVM (native per the sweep); pins the associative XOR-over-sets
        // behavior with insertion-order-preserving Set rendering.
        let src = r#"fun probe() -> Str {
    let a = Set([1, 2, 3, 4])
    let b = Set([3, 4, 5, 6])
    let c = Set([5, 6, 7, 8])
    let sd1 = a.symmetric_difference(b)
    let sd2 = a.symmetric_difference(b).symmetric_difference(c)
    "{sd1}|{sd2}"
}
"#;
        assert_eq!(differential(src), "Set{1, 2, 5, 6}|Set{1, 2, 7, 8}");
    }

    #[test]
    fn diff_map_entries_filter_rebuild() {
        // A certification lock (it267): the Map-rebuild-via-fold idiom. KUPL has no direct
        // Map.filter, so pruning or transforming a map's entries is done by folding over its
        // (key, value) pairs into a FRESH Map with conditional inserts — distinct from map_values
        // (it4526), which keeps every key and transforms values 1:1 and cannot DROP entries. Three
        // rebuilds over an insertion-ordered map: (1) FILTER — keep only v >= 10, dropping apple(3)
        // and cherry(5), leaving Map{"banana": 12, "date": 20} with surviving entries in their
        // original insertion order; (2) rebuild transforming VALUES (v * 2 -> [6, 24, 10, 40]); (3)
        // rebuild transforming KEYS ("{k}!" -> ["apple!", "banana!", "cherry!", "date!"]). Byte-
        // identical on interp/KVM (native per the sweep). Pins that a fold into a new Map preserves
        // the survivors' insertion order and that entries can be dropped, re-valued, or re-keyed.
        let src = r#"fun probe() -> Str {
    let m = Map().insert("apple", 3).insert("banana", 12).insert("cherry", 5).insert("date", 20)
    let kept = m.fold(Map(), fn(acc, k, v) {
        if v >= 10 { acc.insert(k, v) } else { acc }
    })
    let doubled = m.fold(Map(), fn(acc, k, v) { acc.insert(k, v * 2) })
    let renamed = m.fold(Map(), fn(acc, k, v) { acc.insert("{k}!", v) })
    "{kept}|{doubled.values()}|{renamed.keys()}"
}
"#;
        assert_eq!(
            differential(src),
            r#"Map{"banana": 12, "date": 20}|[6, 24, 10, 40]|["apple!", "banana!", "cherry!", "date!"]"#
        );
    }

    #[test]
    fn diff_match_newline_arms_in_varied_paren_positions() {
        // A bug-hunt-27 lock (it266): broadens the it265 parser fix beyond the map/fold-closure case
        // to every paren-nesting position a newline-separated `match` can appear in, guarding against
        // a narrow regression. Three positions that all sit inside an open `(`/`[`: (1) a `match` in
        // a `.map(fn x { ... })` closure body; (2) a `match` inside a predicate closure passed to
        // `.all()` which is itself the condition of an `if`; (3) `match` expressions used directly as
        // LIST-LITERAL elements with their arms split across lines. All parse with newline-separated
        // arms and run byte-identically on interp/KVM (native per the sweep).
        let src = r#"fun probe() -> Str {
    let a = [0, 1, 2].map(fn x {
        match x {
            0 => "zero"
            1 => "one"
            _ => "many"
        }
    })
    let b = if [1, 2].all(fn x { match x { 0 => false, _ => true } }) { "allnz" } else { "has0" }
    let c = [match 1 { 1 => "y"
                       _ => "n" }, match 2 { 2 => "yy"
                                             _ => "nn" }]
    "{a}|{b}|{c}"
}
"#;
        assert_eq!(differential(src), r#"["zero", "one", "many"]|allnz|["y", "yy"]"#);
    }

    #[test]
    fn diff_match_newline_arms_inside_call_arg_closure() {
        // A real parser fix (it265): a `match` with NEWLINE-separated arms inside a call-argument
        // closure (paren context) used to fail with a bogus K0109. The lexer suppresses newlines
        // while inside `(`/`[` (for line continuation), but a `{` block — a closure body, match/if
        // block, or statement block — re-opens a statement context where newlines are significant
        // again. Before the fix, the newlines separating the match arms in
        // `xs.map(fn x { match x { 1 => .. \n _ => .. } })` were swallowed and the second arm read as
        // "another arm on the same line". The fix saves paren depth on `{` and resets it to 0.
        // This certifies the fix AND the Result-collect idiom that motivated it: fold a List[Str]
        // into a Result[List[Int], Str], short-circuiting to the FIRST parse error, all with
        // newline-separated match arms inside the fold's closure. Byte-identical on interp/KVM
        // (native per the sweep).
        let src = r#"fun collect(items: List[Str]) -> Result[List[Int], Str] {
    items.fold(Ok([]), fn(acc, s) {
        match acc {
            Ok(nums) => match s.parse_int() {
                Some(n) => Ok(nums.push(n))
                None => Err("bad: {s}")
            }
            Err(e) => Err(e)
        }
    })
}
fun probe() -> Str {
    let mt: List[Str] = []
    "{collect(["1", "2", "3"])}|{collect(["1", "x", "3"])}|{collect(["a", "b", "3"])}|{collect(mt)}"
}
"#;
        assert_eq!(
            differential(src),
            r#"Ok([1, 2, 3])|Err("bad: x")|Err("bad: a")|Ok([])"#
        );
    }

    #[test]
    fn diff_if_let_while_let_applied_idioms() {
        // A certification lock (it264): the APPLIED if-let/while-let idioms, complementing it125's
        // mechanics test (which covers if-let-as-expression with nested patterns, statement-scope
        // binding, and counter-driven while-let). This pins three distinct real-world uses: (1)
        // if-let over Map.get() with a mutating else branch — the lookup-with-fallback pattern where
        // a hit adds the value and a miss adds a default (get("a")=Some(1) -> acc 1, get("z")=None ->
        // else acc+10 = 11); (2) while-let DRAINING a list by peeking first() and dropping, consuming
        // it front-to-back until empty ("5,7,9,4,3,"), distinct from it125's step(n) counter; (3)
        // if-let DRIVING RECURSION — first_even walks a list via if-let on first() and recurses on
        // drop(1), returning Some(8) for [1,3,5,8,9] and None for [1,3,5]. Byte-identical on
        // interp/KVM (native per the sweep).
        let src = r#"fun first_even(xs: List[Int]) -> Option[Int] {
    if let Some(x) = xs.first() {
        if x % 2 == 0 { Some(x) } else { first_even(xs.drop(1)) }
    } else {
        None
    }
}
fun probe() -> Str {
    let m = Map().insert("a", 1).insert("b", 2)
    var acc = 0
    if let Some(v) = m.get("a") { acc = acc + v } else { acc = acc - 1 }
    if let Some(v) = m.get("z") { acc = acc + 100 } else { acc = acc + 10 }
    var xs = [5, 7, 9, 4, 3]
    var drained = ""
    while let Some(h) = xs.first() {
        drained = "{drained}{h},"
        xs = xs.drop(1)
    }
    "{acc}|{drained}|{first_even([1, 3, 5, 8, 9])}|{first_even([1, 3, 5])}"
}
"#;
        assert_eq!(differential(src), "11|5,7,9,4,3,|Some(8)|None");
    }

    #[test]
    fn diff_group_by_then_map_values_histogram() {
        // A bug-hunt-25 lock (it262): the frequency-table / count-by-category idiom. group_by alone
        // (it1978), map-from-pairs+group_by (it2553), and map_values alone (it4526) are locked; this
        // pins the CHAIN group_by(key) -> map_values(len) that turns a list into a histogram of counts
        // per bucket. Words bucketed by first letter give Map{"a": [apple, avocado, apricot],
        // "b": [banana, blueberry], "c": [cherry]} in first-seen key order, then map_values reduces
        // each bucket's list to its length, yielding Map{"a": 3, "b": 2, "c": 1}. Byte-identical on
        // interp/KVM (native per the sweep). Pins that group_by's first-seen key order survives the
        // map_values pass and that each bucket's element count is exact -- the word-frequency /
        // tally-by-key idiom. (zip_with truncate-to-shorter was already locked at it1983.)
        let src = r#"fun probe() -> Str {
    let words = ["apple", "banana", "avocado", "cherry", "blueberry", "apricot"]
    let byfirst = words.group_by(fn w { w.chars().first().unwrap_or("?") })
    let counts = byfirst.map_values(fn ws { ws.len() })
    "{counts}"
}
"#;
        assert_eq!(differential(src), r#"Map{"a": 3, "b": 2, "c": 1}"#);
    }

    #[test]
    fn diff_partition_then_process_each_side() {
        // A certification lock (it261): the split-and-route idiom. partition() itself is locked
        // (it1993/3857); this pins the common downstream pattern of extracting BOTH sides via
        // first()/last() and running a DIFFERENT pipeline on each — the valid/invalid, pass/fail,
        // in-range/out-of-range bucketing an AI writes constantly. partition(x >= 10) over
        // [12,3,45,7,89,2,100] yields ([12,45,89,100], [3,7,2]) with each side preserving original
        // relative order; then the big side is sorted ([12,45,89,100]) and the small side is doubled
        // ([6,14,4]), with a count of the big side (4) and a sum of the small side (12). Byte-identical
        // on interp/KVM (native per the sweep). Pins that partition is [matching, non-matching],
        // order-preserving, and that the two sides route independently through distinct transforms.
        let src = r#"fun probe() -> Str {
    let nums = [12, 3, 45, 7, 89, 2, 100]
    let parts = nums.partition(fn x { x >= 10 })
    let big = parts.first().unwrap_or([])
    let small = parts.last().unwrap_or([])
    let bigsorted = big.sort_by(fn x { x })
    let smalldoubled = small.map(fn x { x * 2 })
    let bigcount = big.len()
    let smallsum = small.fold(0, fn(a, x) { a + x })
    "{bigsorted}|{smalldoubled}|{bigcount}|{smallsum}"
}
"#;
        assert_eq!(differential(src), "[12, 45, 89, 100]|[6, 14, 4]|4|12");
    }

    #[test]
    fn diff_nested_flat_map_cartesian_product() {
        // A bug-hunt-24 lock (it260): NESTED flat_map — the two-level monadic bind that generates a
        // cartesian product / nested list comprehension. Single-level flat_map (1->N expand,
        // empty-as-filter) is locked at it1989/3856; this pins flat_map INSIDE flat_map, where the
        // outer closure's bound variable is still in scope in the inner closure. [1,2,3] x ["x","y"]
        // yields the full cross product ["1x","1y",...,"3y"]; [0,1] x [0,1,2] yields grid coordinates
        // [0,1,2,10,11,12]; and the third uses an empty-list return in the INNER flat_map as a filter
        // to emit only upper-triangle pairs where b > a (["1-2","1-3","2-3"]). Byte-identical on
        // interp/KVM (native per the sweep). This is the nested-comprehension / pair-generation idiom.
        let src = r#"fun probe() -> Str {
    let pairs = [1, 2, 3].flat_map(fn a { ["x", "y"].flat_map(fn b { ["{a}{b}"] }) })
    let coords = [0, 1].flat_map(fn r { [0, 1, 2].flat_map(fn c { [r * 10 + c] }) })
    let triangle = [1, 2, 3].flat_map(fn a { [1, 2, 3].flat_map(fn b { if b > a { ["{a}-{b}"] } else { [] } }) })
    "{pairs}|{coords}|{triangle}"
}
"#;
        assert_eq!(
            differential(src),
            r#"["1x", "1y", "2x", "2y", "3x", "3y"]|[0, 1, 2, 10, 11, 12]|["1-2", "1-3", "2-3"]"#
        );
    }

    #[test]
    fn diff_chunk_then_aggregate_batch_processing() {
        // A certification lock (it259): the batch-processing idiom, the non-overlapping complement to
        // it257's window->aggregate. chunk(k) splits a list into consecutive NON-overlapping groups
        // (window's were overlapping), and the crucial edge is the PARTIAL LAST CHUNK when the length
        // doesn't divide evenly. chunk(3) over [1..7] gives [[1,2,3],[4,5,6],[7]] — two full batches
        // and a singleton tail — so folding each yields sums [6, 15, 7] and sizes [3, 3, 1]; chunk(2)
        // gives a length-1 tail too (maxes [2, 4, 6, 7]); and [1,2,3,4].chunk(2) divides exactly
        // ([3, 7], no partial). chunk(3).len() == 3 (ceil(7/3)). Byte-identical on interp/KVM (native
        // per the sweep). This pins that the partial tail is neither dropped nor padded.
        let src = r#"fun probe() -> Str {
    let xs = [1, 2, 3, 4, 5, 6, 7]
    let batchsums = xs.chunk(3).map(fn c { c.fold(0, fn(a, x) { a + x }) })
    let batchsizes = xs.chunk(3).map(fn c { c.len() })
    let batchmaxes = xs.chunk(2).map(fn c { c.fold(0, fn(m, x) { if x > m { x } else { m } }) })
    let exact = [1, 2, 3, 4].chunk(2).map(fn c { c.fold(0, fn(a, x) { a + x }) })
    "{batchsums}|{batchsizes}|{batchmaxes}|{exact}|{xs.chunk(3).len()}"
}
"#;
        assert_eq!(
            differential(src),
            "[6, 15, 7]|[3, 3, 1]|[2, 4, 6, 7]|[3, 7]|3"
        );
    }

    #[test]
    fn diff_window_then_aggregate_moving_stats() {
        // A certification lock (it257): the sliding-window aggregation idiom. it165 locked window()
        // producing overlapping sub-lists; this composes it with map + fold to compute a MOVING
        // STATISTIC over each window — the canonical time-series / signal-processing shape.
        // window(3) over [1..6] yields 4 length-3 windows; folding each gives a moving sum
        // [6, 9, 12, 15] and a moving max [3, 4, 5, 6]; window(2).map(first) takes the leading
        // element of each pair. Byte-identical on interp/KVM (native per the sweep).
        let src = r#"fun probe() -> Str {
    let xs = [1, 2, 3, 4, 5, 6]
    let movsum = xs.window(3).map(fn w { w.fold(0, fn(a, x) { a + x }) })
    let movmax = xs.window(3).map(fn w { w.fold(0, fn(m, x) { if x > m { x } else { m } }) })
    let firsts = xs.window(2).map(fn w { w.first().unwrap_or(0) })
    "{movsum}|{movmax}|{firsts}|{xs.window(3).len()}"
}
"#;
        assert_eq!(
            differential(src),
            "[6, 9, 12, 15]|[3, 4, 5, 6]|[1, 2, 3, 4, 5]|4"
        );
    }

    #[test]
    fn diff_match_three_field_ctor_and_nested_if_arm() {
        // A bug-hunt-22 lock (it256): two match shapes the existing Shape tests omit. Prior locks
        // (it1808/3123/4951) use at most 2-field constructors and classify via match GUARDS
        // (`Rect(w, h) if w == h`); this binds a THREE-field constructor `Tri(a, b, c)` and does the
        // classification with a NESTED if in the arm BODY (equilateral -> isosceles -> scalene,
        // deciding on a==b then b==c). The canonical triangle classifier: three simultaneous field
        // bindings and an arm body that is itself a nested conditional. Byte-identical on interp/KVM
        // (native per the sweep).
        let src = r#"type Shape = Circle(r: Int) | Rect(w: Int, h: Int) | Tri(a: Int, b: Int, c: Int)
fun area(s: Shape) -> Int {
    match s {
        Circle(r) => 3 * r * r
        Rect(w, h) => w * h
        Tri(a, b, c) => a + b + c
    }
}
fun classify(s: Shape) -> Str {
    match s {
        Circle(r) => if r > 10 { "big circle" } else { "small circle" }
        Rect(w, h) => if w == h { "square" } else { "rectangle" }
        Tri(a, b, c) => if a == b { if b == c { "equilateral" } else { "isosceles" } } else { "scalene" }
    }
}
fun probe() -> Str {
    "{area(Circle(r: 5))}|{area(Rect(w: 3, h: 4))}|{classify(Rect(w: 5, h: 5))}|{classify(Tri(a: 2, b: 2, c: 2))}|{classify(Tri(a: 2, b: 2, c: 3))}|{classify(Tri(a: 1, b: 2, c: 3))}"
}
"#;
        assert_eq!(differential(src), "75|12|square|equilateral|isosceles|scalene");
    }

    #[test]
    fn diff_result_railway_multistage_short_circuit() {
        // A certification lock (it255): railway-oriented validation — chain several user-defined
        // fallible functions with `and_then`, each returning Result, so the pipeline short-circuits
        // on the FIRST Err and carries that stage's message all the way out. it164/217/3628 locked
        // the Result combinator surface on single-expression chains; this pins a multi-stage
        // parse -> validate-positive -> validate-small -> transform pipeline and demonstrates the
        // short-circuit landing at EACH distinct stage (bad parse, non-positive, too-big) plus the
        // all-success path. Byte-identical on interp/KVM (native per the sweep).
        let src = r#"fun parseNum(s: Str) -> Result[Int, Str] {
    match s.parse_int() {
        Some(n) => Ok(n)
        None => Err("not a number: {s}")
    }
}
fun positive(n: Int) -> Result[Int, Str] { if n > 0 { Ok(n) } else { Err("not positive: {n}") } }
fun small(n: Int) -> Result[Int, Str] { if n < 100 { Ok(n) } else { Err("too big: {n}") } }
fun pipeline(s: Str) -> Result[Int, Str] {
    parseNum(s).and_then(positive).and_then(small).map(fn n { n * 2 })
}
fun probe() -> Str {
    "{pipeline("42")}|{pipeline("abc")}|{pipeline("-5")}|{pipeline("999")}|{pipeline("7").unwrap_or(0)}"
}
"#;
        assert_eq!(
            differential(src),
            r#"Ok(84)|Err("not a number: abc")|Err("not positive: -5")|Err("too big: 999")|14"#
        );
    }

